// ============================================
// @elitegrid/vue — GridHeader
// Renders the column header row.
//
// IDEOLOGY:
// Header is a flex row of header cells. Each header cell renders:
//   • the column label
//   • a sort indicator if sortable
//   • a filter icon if filterable (opens popover)
//   • a resize handle on the right edge if resizable
//
// All interactions go through the engine event bus or plugin methods.
// We never touch column state directly — the engine owns it.
//
// Mirror of react/src/components/GridHeader.tsx
// ============================================

import {
  defineComponent,
  h,
  ref,
  computed,
  onBeforeUnmount,
  type Ref,
} from 'vue'
import { GridEvent } from '@elitegrid/core'
import type { ColumnDefinition } from '@elitegrid/core'
import { useGridContext } from '../context/GridContext'
import {
  useColumnsState,
  useSortedState,
  useFilteredState,
  useViewportState,
  useSelectionState,
} from '../composables/useGridStates'
import { calculateColumnWidths } from '../utils/columnWidths'
import { GridFilterPopover } from './GridFilterPopover'

const DefaultFilterIcon = () =>
  h(
    'svg',
    {
      width: '12',
      height: '12',
      viewBox: '0 0 12 12',
      fill: 'currentColor',
    },
    [h('path', { d: 'M1 2h10L7 6.5V10.5L5 9.5V6.5L1 2z' })]
  )

export const GridHeader = defineComponent({
  name: 'GridHeader',
  props: {},
  setup() {
    const grid = useGridContext()
    const columns = useColumnsState(grid)
    const sorted = useSortedState(grid)
    const viewport = useViewportState(grid)
    const selection = useSelectionState(grid)
    // Subscribe to filtered namespace so the filter icon color updates
    // immediately when a filter is applied or cleared — instead of reading
    // a stale snapshot from the store at render time.
    const filtered = useFilteredState(grid)

    // Filter popover state — which column's popover is open
    const activeFilterColumnId = ref<string | null>(null)
    const hoveredColumnId = ref<string | null>(null)
    const resizingColumnId = ref<string | null>(null)

    // Per-column refs for popover anchors. Built lazily so we don't
    // pay for unrendered columns. Map keyed by columnId.
    const filterIconRefs = new Map<string, Ref<HTMLElement | null>>()
    const getFilterIconRef = (columnId: string) => {
      let r = filterIconRefs.get(columnId)
      if (!r) {
        r = ref<HTMLElement | null>(null)
        filterIconRefs.set(columnId, r)
      }
      return r
    }

    // ── Resize drag state — kept outside reactive system ─────────
    // A ref would trigger re-renders on every mousemove (60+ fps).
    // Plain closure-bound state avoids that — only the engine's
    // COLUMN_RESIZED event re-renders the header.
    let resizeState: {
      columnId: string
      startX: number
      startWidth: number
      minWidth: number
      maxWidth: number | undefined
    } | null = null
    let didResize = false

    // AbortController for document-level drag listeners. If the grid
    // unmounts mid-drag, onBeforeUnmount aborts the controller and the
    // listeners are removed automatically via the signal option.
    let dragAbortController: AbortController | null = null

    onBeforeUnmount(() => {
      dragAbortController?.abort()
      dragAbortController = null
      document.body.style.cursor = ''
      document.body.style.userSelect = ''
    })

    const handleResizeMouseDown = (e: MouseEvent, col: ColumnDefinition) => {
      e.preventDefault()
      e.stopPropagation() // don't trigger sort click

      // Read current width straight from the store — closure widths
      // could be stale if the engine updated between renders.
      const storeWidths = grid.kernel.store.read('columns').widths
      const currentWidth = storeWidths.get(col.id) ?? col.width ?? 150
      const minWidth = col.minWidth ?? 50
      const maxWidth = col.maxWidth

      resizeState = {
        columnId: col.id,
        startX: e.clientX,
        startWidth: currentWidth,
        minWidth,
        maxWidth,
      }
      resizingColumnId.value = col.id

      // Cursor on body — prevents flicker when mouse moves faster than the handle
      document.body.style.cursor = 'col-resize'
      document.body.style.userSelect = 'none'

      const controller = new AbortController()
      dragAbortController = controller
      const { signal } = controller

      const handleMouseMove = (moveEvent: MouseEvent) => {
        if (!resizeState) return
        didResize = true
        const delta = moveEvent.clientX - resizeState.startX
        let newWidth = resizeState.startWidth + delta
        newWidth = Math.max(resizeState.minWidth, newWidth)
        if (resizeState.maxWidth !== undefined) {
          newWidth = Math.min(resizeState.maxWidth, newWidth)
        }
        const currentContainerWidth =
          grid.kernel.store.read('viewport').containerWidth
        grid.plugins.columnModel.setWidth(
          resizeState.columnId,
          Math.floor(newWidth),
          currentContainerWidth
        )
      }

      const handleMouseUp = (upEvent: MouseEvent) => {
        if (!resizeState) return
        const delta = upEvent.clientX - resizeState.startX
        let finalWidth = resizeState.startWidth + delta
        finalWidth = Math.max(resizeState.minWidth, finalWidth)
        if (resizeState.maxWidth !== undefined) {
          finalWidth = Math.min(resizeState.maxWidth, finalWidth)
        }
        const currentContainerWidth =
          grid.kernel.store.read('viewport').containerWidth
        grid.plugins.columnModel.setWidth(
          resizeState.columnId,
          Math.floor(finalWidth),
          currentContainerWidth
        )
        // onColumnResize fires from the create-grid COLUMN_RESIZED listener
        // (setWidth emits it) — not here — so it isn't double-called.

        resizeState = null
        resizingColumnId.value = null
        document.body.style.cursor = ''
        document.body.style.userSelect = ''
        controller.abort()
        if (dragAbortController === controller) dragAbortController = null

        // Block the click event that fires after mouseup so a resize
        // drag doesn't accidentally trigger sort on the column.
        if (didResize) {
          const blockClick = (ev: MouseEvent) => {
            ev.stopPropagation()
            ev.preventDefault()
            document.removeEventListener('click', blockClick, true)
          }
          document.addEventListener('click', blockClick, true)
          setTimeout(() => {
            didResize = false
            document.removeEventListener('click', blockClick, true)
          }, 100)
        }
      }

      document.addEventListener('mousemove', handleMouseMove, { signal })
      document.addEventListener('mouseup', handleMouseUp, { signal })
    }

    const handleSortClick = (columnId: string, sortable: boolean) => {
      if (!sortable) return
      if (grid.options.sorting?.enabled === false) return
      if (didResize) return
      grid.plugins.sort.cycleSort(columnId)
    }

    // Stable Map ref — only rebuilds when definitions or container size change
    const columnWidths = computed(() =>
      calculateColumnWidths(
        columns.value.definitions,
        grid.options.columns,
        viewport.value.containerWidth
      )
    )

    const visibleColumns = computed(() =>
      columns.value.order
        .map((id) => columns.value.definitions.find((d) => d.id === id))
        .filter((col): col is ColumnDefinition => col != null && col.visible)
    )

    return () => {
      const { options } = grid
      const headerHeight = options.appearance?.headerHeight ?? 44
      const filteringOptions = options.filtering
      const iconPosition = filteringOptions?.iconPosition ?? 'right'
      const showIconOnHover = filteringOptions?.showIconOnHover ?? false
      const popoverPlacement = filteringOptions?.popoverPlacement ?? 'auto'

      // Read from the reactive filtered ref (not a snapshot) so the icon
      // updates immediately when filters change.
      const filterModel = filtered.value.filterModel
      const isColumnFiltered = (columnId: string) =>
        columnId in filterModel.columns

      const selectionMode = selection.value.mode
      const isAllSelected = selection.value.isAllSelected
      const isIndeterminate = selection.value.isIndeterminate
      const showCheckboxes =
        selectionMode !== 'none' && (options.selection?.showCheckboxes ?? true)

      // Must match the body spacer minWidth so header and rows always align.
      const totalWidth = viewport.value.totalWidth
      const scrollableWidth = totalWidth + (showCheckboxes ? 48 : 0)

      // Select-all checkbox
      const selectAllCheckbox = showCheckboxes
        ? h(
            'div',
            {
              class: 'yg-header-cell yg-header-cell--checkbox',
              role: 'columnheader',
              'aria-label': 'Select all rows',
              style: {
                width: '48px',
                minWidth: '48px',
                maxWidth: '48px',
                height: '100%',
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'center',
                flexShrink: 0,
                boxSizing: 'border-box',
                borderRight: options.appearance?.showColumnBorders
                  ? 'var(--eg-cell-border)'
                  : undefined,
              },
            },
            [
              h('input', {
                type: 'checkbox',
                'aria-label': 'Select all rows',
                checked: isAllSelected,
                ref: (el) => {
                  if (el && el instanceof HTMLInputElement) {
                    el.indeterminate = isIndeterminate
                  }
                },
                onChange: (e: Event) => {
                  grid.kernel.eventBus.emit(GridEvent.SELECT_ALL_TOGGLED, {
                    checked: (e.target as HTMLInputElement).checked,
                  })
                },
                style: {
                  cursor: 'pointer',
                  width: '16px',
                  height: '16px',
                  accentColor: 'var(--eg-primary)',
                },
              }),
            ]
          )
        : null

      // Per-column header cells
      const headerCells = visibleColumns.value.map((col) => {
        const sortModel = sorted.value.sortModel
        const sortEntry = sortModel.find((s) => s.columnId === col.id)
        const direction = sortEntry?.direction ?? null
        const sortIndex =
          sortModel.length > 1
            ? sortModel.findIndex((s) => s.columnId === col.id) + 1 || null
            : null
        const isSorted = direction !== null
        const isSortable = col.sortable && options.sorting?.enabled !== false
        const isFilterable =
          col.filterable && options.filtering?.enabled !== false
        const isFiltered = isColumnFiltered(col.id)
        const isHovered = hoveredColumnId.value === col.id
        const isResizing = resizingColumnId.value === col.id
        const isResizable = col.resizable !== false
        const colWidth = columnWidths.value.get(col.id) ?? 150

        const showFilterIcon =
          isFilterable &&
          (!showIconOnHover ||
            isHovered ||
            isFiltered ||
            activeFilterColumnId.value === col.id)

        const filterIconRef = getFilterIconRef(col.id)
        const filterIconElement = isFiltered
          ? (filteringOptions?.activeFilterIcon ??
            filteringOptions?.filterIcon ??
            DefaultFilterIcon())
          : (filteringOptions?.filterIcon ?? DefaultFilterIcon())

        const filterIconButton = showFilterIcon
          ? h(
              'div',
              {
                ref: filterIconRef,
                onClick: (e: MouseEvent) => {
                  e.stopPropagation()
                  activeFilterColumnId.value =
                    activeFilterColumnId.value === col.id ? null : col.id
                },
                'aria-label': `Filter ${col.header}`,
                title: `Filter ${col.header}`,
                style: {
                  flexShrink: 0,
                  width: '20px',
                  height: '20px',
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  borderRadius: '4px',
                  cursor: 'pointer',
                  fontSize: '0.75rem',
                  color: isFiltered
                    ? 'var(--eg-primary)'
                    : 'var(--eg-muted-text)',
                  backgroundColor: isFiltered
                    ? 'var(--eg-primary-light)'
                    : activeFilterColumnId.value === col.id
                      ? 'var(--eg-hover-bg)'
                      : 'transparent',
                  transition:
                    'background-color 0.15s, color 0.15s, opacity 0.15s',
                  opacity: showIconOnHover && !isFiltered && !isHovered ? 0 : 1,
                },
              },
              [filterIconElement]
            )
          : showIconOnHover
            ? h('div', { style: { width: '20px', flexShrink: 0 } })
            : null

        const sortIndicator = isSortable
          ? h(
              'span',
              {
                class: 'yg-sort-indicator',
                'aria-hidden': 'true',
                style: {
                  opacity: isSorted ? 1 : 0.3,
                  fontSize: '0.75rem',
                  color: isSorted
                    ? 'var(--eg-sort-active-color)'
                    : 'var(--eg-sort-icon-color)',
                  display: 'flex',
                  alignItems: 'center',
                  gap: '2px',
                  flexShrink: 0,
                },
              },
              [
                direction === 'asc' ? '↑' : direction === 'desc' ? '↓' : '↕',
                sortIndex !== null
                  ? h(
                      'span',
                      { style: { fontSize: '0.65rem' } },
                      String(sortIndex)
                    )
                  : null,
              ]
            )
          : null

        const resizeHandle = isResizable
          ? h(
              'div',
              {
                class: 'yg-resize-handle',
                onMousedown: (e: MouseEvent) => handleResizeMouseDown(e, col),
                onClick: (e: MouseEvent) => e.stopPropagation(),
                'aria-hidden': 'true',
                style: {
                  position: 'absolute',
                  right: '-4px',
                  top: 0,
                  bottom: 0,
                  width: '12px',
                  cursor: 'col-resize',
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  zIndex: 2,
                },
              },
              [
                h('div', {
                  style: {
                    width: '2px',
                    height: isHovered || isResizing ? '60%' : '30%',
                    borderRadius: '1px',
                    backgroundColor: isResizing
                      ? 'var(--eg-primary)'
                      : isHovered
                        ? 'var(--eg-border-hover)'
                        : 'var(--eg-border)',
                    transition: 'height 0.15s, background-color 0.15s',
                  },
                }),
              ]
            )
          : null

        return h(
          'div',
          {
            key: col.id,
            class: [
              'yg-header-cell',
              isSorted ? 'yg-header-cell--sorted' : '',
              isSortable ? 'yg-header-cell--sortable' : '',
              isFiltered ? 'yg-header-cell--filtered' : '',
              isResizing ? 'yg-header-cell--resizing' : '',
            ]
              .filter(Boolean)
              .join(' '),
            role: 'columnheader',
            'aria-sort':
              direction === 'asc'
                ? 'ascending'
                : direction === 'desc'
                  ? 'descending'
                  : 'none',
            onMouseenter: () => (hoveredColumnId.value = col.id),
            onMouseleave: () => (hoveredColumnId.value = null),
            onClick: () => handleSortClick(col.id, col.sortable),
            style: {
              width: `${colWidth}px`,
              minWidth: `${colWidth}px`,
              maxWidth: `${colWidth}px`,
              height: '100%',
              display: 'flex',
              alignItems: 'center',
              padding: '0 12px',
              cursor: isSortable ? 'pointer' : 'default',
              userSelect: 'none',
              fontWeight: 600,
              fontSize: '0.875rem',
              color: 'var(--eg-header-text)',
              borderRight: options.appearance?.showColumnBorders
                ? 'var(--eg-cell-border)'
                : undefined,
              boxSizing: 'border-box',
              flexShrink: 0,
              gap: '4px',
              position: 'relative',
              backgroundColor: isResizing
                ? 'var(--eg-header-active-bg)'
                : undefined,
            },
          },
          [
            iconPosition === 'left' ? filterIconButton : null,
            h(
              'span',
              {
                style: {
                  flex: 1,
                  overflow: 'hidden',
                  textOverflow: 'ellipsis',
                },
              },
              col.header
            ),
            sortIndicator,
            iconPosition === 'right' ? filterIconButton : null,
            resizeHandle,
          ]
        )
      })

      // Filter popover (rendered as sibling so it can position fixed)
      const activeColId = activeFilterColumnId.value
      const popover = activeColId
        ? h(GridFilterPopover, {
            columnId: activeColId,
            filterType: (options.columns.find(
              (c) => (c.field as string) === activeColId
            )?.filter?.type ?? 'text') as 'text' | 'number' | 'date' | 'boolean',
            anchorRef: getFilterIconRef(activeColId),
            onClose: () => {
              activeFilterColumnId.value = null
            },
            placement: popoverPlacement,
          })
        : null

      // Return array (Vue 3 multi-root). Header is sticky inside the unified
      // scroll container; popover uses position:fixed so placement is unaffected.
      return [
        h(
          'div',
          {
            class: 'yg-header',
            role: 'rowgroup',
            style: {
              // Sticky inside the unified scroll container — stays at the top
              // during vertical scroll; moves horizontally with the content
              // (same container) so header and rows are always in perfect
              // alignment with zero JavaScript sync.
              position: 'sticky',
              top: 0,
              zIndex: 2,
              height: `${headerHeight}px`,
              minHeight: `${headerHeight}px`,
              // Must be at least as wide as the scrollable content so column
              // headers extend to the right edge as the user scrolls.
              minWidth: `${scrollableWidth}px`,
              display: 'flex',
              flexDirection: 'row',
              borderBottom: 'var(--eg-header-border)',
              backgroundColor: 'var(--eg-header-bg)',
              flexShrink: 0,
              cursor: resizingColumnId.value ? 'col-resize' : undefined,
            },
          },
          [selectAllCheckbox, ...headerCells]
        ),
        popover,
      ]
    }
  },
})
