// ============================================
// @elitegrid/vue — useStoreNamespace (internal)
// Generic composable that bridges the engine's
// store to Vue's reactivity system.
//
// IDEOLOGY:
// The engine has its own subscription model:
//   store.subscribe(namespace, callback) → unsubscribe
// Vue has its own reactivity primitive:
//   ref(value).value  (mutating .value triggers re-render)
//
// Bridging the two = the heart of any framework adapter.
//
// Strategy:
//   1. Read the namespace's current state.
//   2. Wrap it in `shallowRef` so mutating `.value` triggers a
//      re-render WITHOUT making the inner object deeply reactive.
//      (Deep reactivity would wrap Map/Set values which the
//      store uses for columnWidths, selectedIds etc.)
//   3. Subscribe to the namespace; on every change, replace .value.
//   4. Tear down the subscription on unmount.
//
// Every specific composable (useViewportState, useColumnsState, …)
// is a thin wrapper around this.
// ============================================

import { shallowRef, onMounted, onBeforeUnmount, type Ref } from 'vue'
import type { StoreState, NamespaceKey } from '@elitegrid/core'
import type { GridInstance } from '../create-grid'

// `Ref<T>` is Vue's reactive container type. `.value` access
// is what triggers tracking. We return Readonly to discourage
// downstream mutation — only the engine should write store state.
export function useStoreNamespace<K extends NamespaceKey>(
  grid: GridInstance,
  namespace: K
): Readonly<Ref<StoreState[K]>> {
  // shallowRef vs ref:
  //   ref() recursively makes the value reactive (proxies every nested
  //   field). For a grid this is expensive and breaks Map/Set behaviour.
  //   shallowRef only tracks the `.value` slot — a new object reference
  //   counts as a change, but mutations inside the object don't.
  //   The store ALREADY emits new shallow-copied objects on every write
  //   (see DataStore.notify in core), so shallowRef + reference equality
  //   is exactly the contract we want.
  //
  // We cast to `Ref<StoreState[K]>` because Vue's shallowRef type
  // overloads don't infer the generic indexed type correctly — the
  // narrower per-namespace composables (useColumnsState, etc.) re-cast
  // back to the specific namespace shape, so this stays type-safe at
  // the public boundary.
  const state = shallowRef(grid.kernel.store.read(namespace)) as Ref<
    StoreState[K]
  >

  let unsubscribe: (() => void) | null = null

  onMounted(() => {
    // Re-read on mount in case state changed between setup() and onMounted().
    // setup() runs synchronously when the component is created; if anything
    // in the same tick (e.g. an event handler firing during initial render)
    // mutated the store, we'd have a stale first paint without this sync.
    state.value = grid.kernel.store.read(namespace)

    unsubscribe = grid.kernel.store.subscribe(namespace, (next) => {
      // Assigning .value triggers Vue's dependency system → re-renders
      // every component that read `state.value` during its render pass.
      state.value = next as StoreState[K]
    })
  })

  onBeforeUnmount(() => {
    unsubscribe?.()
    unsubscribe = null
  })

  return state
}
