// ============================================
// @elitegrid/core — Pagination Plugin
// Third step in the data pipeline
// Reads from 'sorted' namespace
// Writes to 'paginated' namespace
// ============================================

import type { Plugin, PluginContext } from '../../kernel/index'
import { GridEvent } from '../../event-bus/events'
import { devWarn } from '../../utils/dev'

// ── Plugin ID ─────────────────────────────────

export const PAGINATION_PLUGIN_ID = 'pagination'

// ── Config ────────────────────────────────────

export interface PaginationConfig {
  enabled?: boolean // default: true
  pageSize?: number // default: 25
  pageSizeOptions?: number[] // default: [10, 25, 50, 100]
}

// ── Implementation ─────────────────────────────

export class PaginationPlugin implements Plugin {
  readonly id = PAGINATION_PLUGIN_ID

  private context!: PluginContext
  private config: PaginationConfig = {}

  // Current pagination state
  private currentPage: number = 1
  private pageSize: number = 25
  private enabled: boolean = true

  // Cleanup functions
  private cleanups: Array<() => void> = []

  // ── Configure ─────────────────────────────

  configure(config: PaginationConfig): void {
    this.config = config
    this.enabled = config.enabled ?? true
    this.pageSize = config.pageSize ?? 25
  }

  // ── Init ──────────────────────────────────

  init(context: PluginContext): void {
    this.context = context

    // When sort completes — paginate new sorted rows
    this.cleanups.push(
      context.eventBus.on(GridEvent.SORT_COMPLETED, this.handleSortCompleted)
    )

    // When filter completes — reset to page 1 and paginate
    this.cleanups.push(
      context.eventBus.on(
        GridEvent.FILTER_COMPLETED,
        this.handleFilterCompleted
      )
    )

    // Run initial pagination pass
    this.applyPagination()
  }

  // ── Event Handlers ─────────────────────────

  private handleSortCompleted = (): void => {
    // Sort changed rows — re-paginate
    // Stay on current page
    this.applyPagination()
  }

  private handleFilterCompleted = (): void => {
    // Filter changed rows — reset to page 1
    this.resetToFirstPage()
  }

  // ── Reset To First Page ────────────────────

  private resetToFirstPage(): void {
    const wasOnPageOne = this.currentPage === 1
    this.currentPage = 1

    // Always apply pagination with new filtered rows
    this.applyPagination()

    // Only emit PAGE_CHANGED if we actually moved pages
    if (!wasOnPageOne) {
      this.context.eventBus.emit(GridEvent.PAGE_CHANGED, {
        page: 1,
        pageSize: this.pageSize,
      })
    }
  }

  // ── Apply Pagination ───────────────────────

  private applyPagination(): void {
    const { rows } = this.context.store.read('sorted')
    const totalRows = rows.length

    // Calculate derived values
    const totalPages =
      totalRows === 0 ? 0 : Math.ceil(totalRows / this.pageSize)

    // Clamp currentPage to valid range
    // Handles case where filter reduces total pages
    // below current page number
    if (totalPages > 0 && this.currentPage > totalPages) {
      this.currentPage = totalPages
    }

    // Calculate row range — 1-based for display
    const startRow =
      totalRows === 0 ? 0 : (this.currentPage - 1) * this.pageSize + 1

    const endRow = Math.min(this.currentPage * this.pageSize, totalRows)

    // Slice correct page — 0-based for array
    const startIndex = (this.currentPage - 1) * this.pageSize
    const endIndex = startIndex + this.pageSize

    const pageRows = this.enabled ? rows.slice(startIndex, endIndex) : rows // pagination disabled — return all rows

    // Write to paginated namespace
    this.context.store.write('paginated', {
      rows: pageRows,
      currentPage: this.currentPage,
      pageSize: this.pageSize,
      totalPages,
      totalRows,
      startRow,
      endRow,
      hasNextPage: this.currentPage < totalPages,
      hasPreviousPage: this.currentPage > 1,
    })

    // Notify pipeline — viewport listens to this
    this.context.eventBus.emit(GridEvent.PAGINATED_DATA_CHANGED)
  }

  // ── Public API ─────────────────────────────

  setPage(page: number): void {
    const { totalPages } = this.context.store.read('paginated')

    // Clamp to valid range
    const clampedPage = Math.min(Math.max(1, page), Math.max(1, totalPages))

    if (clampedPage === this.currentPage) return

    this.currentPage = clampedPage
    this.applyPagination()

    this.context.eventBus.emit(GridEvent.PAGE_CHANGED, {
      page: this.currentPage,
      pageSize: this.pageSize,
    })
  }

  setPageSize(size: number): void {
    if (size <= 0) {
      devWarn(
        `[EliteGrid] setPageSize(${size}) ignored — page size must be a positive integer.`
      )
      return
    }
    if (size === this.pageSize) return

    this.pageSize = size
    this.currentPage = 1
    this.applyPagination()

    this.context.eventBus.emit(GridEvent.PAGE_SIZE_CHANGED, {
      pageSize: size,
    })
  }

  nextPage(): void {
    const { hasNextPage } = this.context.store.read('paginated')
    if (hasNextPage) {
      this.setPage(this.currentPage + 1)
    }
  }

  previousPage(): void {
    const { hasPreviousPage } = this.context.store.read('paginated')
    if (hasPreviousPage) {
      this.setPage(this.currentPage - 1)
    }
  }

  firstPage(): void {
    this.setPage(1)
  }

  lastPage(): void {
    const { totalPages } = this.context.store.read('paginated')
    this.setPage(totalPages)
  }

  getPaginationState() {
    return this.context.store.read('paginated')
  }

  getCurrentPage(): number {
    return this.currentPage
  }

  getPageSize(): number {
    return this.pageSize
  }

  // ── Destroy ───────────────────────────────

  destroy(): void {
    this.cleanups.forEach((cleanup) => cleanup())
    this.cleanups = []
  }
}
