// ============================================
// @elitegrid/vue — GridCellEditor
// Inline cell editor — text, number, select, date, boolean.
//
// IDEOLOGY:
// EditPlugin owns editor state (currentValue, isValid, error).
// This component renders an `<input>` / `<select>` and emits
// engine events on user interaction:
//
//   • EDIT_VALUE_CHANGED   — keystroke / option change
//   • EDIT_COMMIT_REQUESTED — Enter, blur, or Tab
//   • EDIT_CANCEL_REQUESTED — Escape
//   • FOCUS_MOVE_REQUESTED  — Tab moves to next editable cell
//
// All event handlers go through the engine event bus — no
// direct plugin method calls — keeps the adapter framework-agnostic
// in spirit. Plugin reactions happen inside the engine.
//
// Fixes applied:
//   • committed guard prevents double-commit on blur-after-Tab/Enter
//   • boolean editor uses onMounted in setup() (not inside render)
//   • date parsing/formatting uses local time (not UTC)
//   • validation tooltip is Teleported to <body> with fixed positioning
//
// Mirror of react/src/components/GridCellEditor.tsx
// ============================================

import {
  defineComponent,
  h,
  ref,
  onMounted,
  onBeforeUnmount,
  Teleport,
  type PropType,
  type Ref,
} from 'vue'
import { GridEvent } from '@elitegrid/core'
import type { CellPosition, ColumnEditorConfig } from '@elitegrid/core'
import { useGridContext } from '../context/GridContext'
import { parseLocalDate, formatDateInput } from '../utils/date'

// ── ValidationTooltip ─────────────────────────────────────────
// Rendered into <body> via Teleport so overflow:hidden on the cell
// can't clip it. position:fixed with coordinates read from the
// input's getBoundingClientRect — recalculated on scroll/resize.

const ValidationTooltip = defineComponent({
  name: 'ValidationTooltip',
  props: {
    message: { type: String, required: true },
    inputRef: {
      type: Object as PropType<
        Ref<HTMLInputElement | HTMLSelectElement | null>
      >,
      required: true,
    },
  },
  setup(props) {
    const pos = ref<{ top: number; left: number } | null>(null)

    const update = () => {
      const el = props.inputRef.value
      if (!el) {
        pos.value = null
        return
      }
      const rect = el.getBoundingClientRect()
      pos.value = { top: rect.bottom + 2, left: rect.left }
    }

    onMounted(() => {
      update()
      window.addEventListener('resize', update)
      window.addEventListener('scroll', update, true)
    })

    onBeforeUnmount(() => {
      window.removeEventListener('resize', update)
      window.removeEventListener('scroll', update, true)
    })

    return () => {
      const p = pos.value
      if (!p) return null
      return h(Teleport, { to: 'body' }, [
        h(
          'div',
          {
            role: 'alert',
            style: {
              position: 'fixed',
              top: `${p.top}px`,
              left: `${p.left}px`,
              zIndex: 9999,
              backgroundColor: 'var(--eg-error)',
              color: 'var(--eg-error-text)',
              fontSize: '0.75rem',
              padding: '3px 8px',
              borderRadius: '4px',
              whiteSpace: 'nowrap',
              boxShadow: '0 2px 8px rgba(0,0,0,0.15)',
              pointerEvents: 'none',
            },
          },
          props.message
        ),
      ])
    }
  },
})

export const GridCellEditor = defineComponent({
  name: 'GridCellEditor',
  props: {
    cell: { type: Object as PropType<CellPosition>, required: true },
    currentValue: { type: null, default: null },
    isValid: { type: Boolean, default: true },
    validationError: { type: String as PropType<string | null>, default: null },
    editorConfig: {
      type: Object as PropType<ColumnEditorConfig | null>,
      default: null,
    },
    colWidth: { type: Number, required: true },
    rowHeight: { type: Number, default: 40 },
  },
  setup(props) {
    const grid = useGridContext()
    const inputRef = ref<HTMLInputElement | HTMLSelectElement | null>(null)

    // ── Double-commit guard ───────────────────────────────────────────
    // Tab/Enter call emitCommit(), then the blur handler fires and would
    // call emitCommit() again. The flag makes only the first call emit.
    let committed = false

    const emitChange = (value: unknown) => {
      grid.kernel.eventBus.emit(GridEvent.EDIT_VALUE_CHANGED, {
        cell: props.cell,
        value,
      })
    }
    const emitCommit = () => {
      if (committed) return
      committed = true
      grid.kernel.eventBus.emit(GridEvent.EDIT_COMMIT_REQUESTED, {
        cell: props.cell,
      })
    }
    const emitCancel = () => {
      if (committed) return
      committed = true
      grid.kernel.eventBus.emit(GridEvent.EDIT_CANCEL_REQUESTED, {
        cell: props.cell,
      })
    }

    // ── Boolean editor: toggle + commit once on mount ────────────────
    // Composition-API lifecycle hooks MUST be called inside setup(),
    // not inside the render function. We gate by editor type here.
    let boolTimer: ReturnType<typeof setTimeout> | null = null

    onMounted(() => {
      const editorType = props.editorConfig?.type ?? 'text'
      if (editorType === 'boolean') {
        const toggled = !props.currentValue
        emitChange(toggled)
        boolTimer = setTimeout(() => emitCommit(), 0)
        return
      }
      const el = inputRef.value
      if (!el) return
      el.focus()
      if (el instanceof HTMLInputElement) el.select()
    })

    onBeforeUnmount(() => {
      if (boolTimer !== null) {
        clearTimeout(boolTimer)
        boolTimer = null
      }
    })

    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.key === 'Enter') {
        e.preventDefault()
        emitCommit()
      } else if (e.key === 'Escape') {
        e.preventDefault()
        emitCancel()
      } else if (e.key === 'Tab') {
        e.preventDefault()
        emitCommit()
        grid.kernel.eventBus.emit(GridEvent.FOCUS_MOVE_REQUESTED, {
          direction: e.shiftKey ? 'prev' : 'next',
          editableOnly: true,
        })
      }
    }

    return () => {
      const editorType = props.editorConfig?.type ?? 'text'
      const baseStyle = {
        width: '100%',
        height: `${props.rowHeight - 4}px`,
        boxSizing: 'border-box' as const,
        border: props.isValid
          ? '2px solid var(--eg-primary)'
          : '2px solid var(--eg-error)',
        borderRadius: '4px',
        padding: '0 8px',
        fontSize: '0.875rem',
        color: 'var(--eg-cell-text)',
        backgroundColor: 'var(--eg-row-bg)',
        outline: 'none',
      }

      const tooltip =
        !props.isValid && props.validationError
          ? h(ValidationTooltip, {
              message: props.validationError,
              inputRef,
            })
          : null

      // ── Boolean editor — no UI ──────────────
      if (editorType === 'boolean') return null

      // ── Select editor ─────────────────────────
      if (editorType === 'select') {
        const opts = Array.isArray(props.editorConfig?.options)
          ? props.editorConfig.options
          : []
        return h('div', { style: { position: 'relative', width: '100%' } }, [
          h(
            'select',
            {
              ref: inputRef,
              value: String(props.currentValue ?? ''),
              onChange: (e: Event) =>
                emitChange((e.target as HTMLSelectElement).value),
              onKeydown: handleKeyDown,
              onBlur: emitCommit,
              style: { ...baseStyle, cursor: 'pointer' },
            },
            opts.map((opt) =>
              h(
                'option',
                { key: String(opt.value), value: String(opt.value) },
                opt.label
              )
            )
          ),
          tooltip,
        ])
      }

      // ── Date editor ───────────────────────────
      if (editorType === 'date') {
        const dateValue = formatDateInput(props.currentValue)
        const minVal = props.editorConfig?.minDate
          ? formatDateInput(props.editorConfig.minDate)
          : undefined
        const maxVal = props.editorConfig?.maxDate
          ? formatDateInput(props.editorConfig.maxDate)
          : undefined
        return h('div', { style: { position: 'relative', width: '100%' } }, [
          h('input', {
            ref: inputRef,
            type: 'date',
            value: dateValue,
            min: minVal,
            max: maxVal,
            onInput: (e: Event) => {
              const v = (e.target as HTMLInputElement).value
              emitChange(v ? parseLocalDate(v) : null)
            },
            onKeydown: handleKeyDown,
            onBlur: emitCommit,
            style: baseStyle,
          }),
          tooltip,
        ])
      }

      // ── Number editor ─────────────────────────
      if (editorType === 'number') {
        return h('div', { style: { position: 'relative', width: '100%' } }, [
          h('input', {
            ref: inputRef,
            type: 'number',
            value:
              props.currentValue === null || props.currentValue === undefined
                ? ''
                : String(props.currentValue),
            min: props.editorConfig?.min,
            max: props.editorConfig?.max,
            step: (props.editorConfig as { step?: number } | null)?.step ?? 1,
            onInput: (e: Event) => {
              const v = (e.target as HTMLInputElement).value
              emitChange(v === '' ? null : Number(v))
            },
            onKeydown: handleKeyDown,
            onBlur: emitCommit,
            style: baseStyle,
          }),
          tooltip,
        ])
      }

      // ── Text editor (default) ─────────────────
      return h('div', { style: { position: 'relative', width: '100%' } }, [
        h('input', {
          ref: inputRef,
          type: 'text',
          value:
            props.currentValue === null || props.currentValue === undefined
              ? ''
              : String(props.currentValue),
          onInput: (e: Event) =>
            emitChange((e.target as HTMLInputElement).value),
          onKeydown: handleKeyDown,
          onBlur: emitCommit,
          style: baseStyle,
        }),
        tooltip,
      ])
    }
  },
})
