// ============================================
// @elitegrid/vue — useExport
// Returns a triggerExport() function for toolbars.
//
// IDEOLOGY:
// The export plugin owns CSV generation. The adapter owns the
// DOM download (creating a Blob, anchor, click). useExport just
// wires the trigger call — the file download itself happens
// inside the <Grid> component when EXPORT_COMPLETED fires.
// ============================================

import type { GridInstance } from '../create-grid'

export interface ExportTriggerOptions {
  scope?: 'all' | 'filtered' | 'page' | 'selected'
  filename?: string
}

export function useExport(grid: GridInstance) {
  const triggerExport = (overrides?: ExportTriggerOptions) => {
    const defaults = grid.options.export ?? {}
    grid.plugins.export.export({
      scope: overrides?.scope ?? defaults.scope ?? 'filtered',
      filename: overrides?.filename ?? defaults.filename ?? 'export',
    })
  }

  return { triggerExport }
}
