// ============================================
// @elitegrid/core — DataSource Plugin
// Loads data into the engine
// Owns the 'raw' namespace in Data Store
// ============================================

import type { Plugin, PluginContext } from '../../kernel/index'
import { GridEvent } from '../../event-bus/events'
import type { IDataSource, DataSourceParams } from '../../types/index'
import { devError } from '../../utils/dev'

// ── Plugin ID ─────────────────────────────────

export const DATA_SOURCE_PLUGIN_ID = 'data-source'

// ── Config ────────────────────────────────────
// What the adapter passes to configure this plugin

export interface DataSourceConfig<TData = unknown> {
  // Option 1 — static array
  data?: TData[]

  // Option 2 — async data source
  dataSource?: IDataSource<TData>

  // Initial page size
  pageSize?: number

  // Which field to use as the row ID — must match RowModelPlugin config
  // Default: 'id'
  rowId?: string | ((row: TData) => string)
}

// ── Implementation ─────────────────────────────

export class DataSourcePlugin<TData = unknown> implements Plugin {
  readonly id = DATA_SOURCE_PLUGIN_ID

  private context!: PluginContext
  private config: DataSourceConfig<TData> = {}

  // Track in-flight request to cancel stale responses
  private currentRequestId: number = 0

  // Cleanup functions
  private cleanups: Array<() => void> = []

  // ── Configure ─────────────────────────────

  configure(config: DataSourceConfig<TData>): void {
    this.config = config
  }

  // ── Init ──────────────────────────────────

  init(context: PluginContext): void {
    this.context = context

    // Listen for refresh requests
    this.cleanups.push(
      context.eventBus.on(GridEvent.DATA_REFRESH_REQUESTED, this.handleRefresh)
    )

    // Load initial data
    this.load()
  }

  // ── Load Data ─────────────────────────────

  async load(params?: Partial<DataSourceParams>): Promise<void> {
    const { data, dataSource } = this.config

    // Scenario 1 — static array provided
    if (data !== undefined) {
      this.loadStatic(data)
      return
    }

    // Scenario 2 — async data source provided
    if (dataSource !== undefined) {
      await this.loadAsync(dataSource, params)
      return
    }

    // Neither provided — set empty state
    this.context.store.write('raw', {
      rows: [],
      totalCount: 0,
      loading: false,
      error: null,
    })
  }

  // ── Static Load ───────────────────────────

  private loadStatic(data: TData[]): void {
    // Guard: null or undefined is a developer mistake, not an empty dataset.
    // An empty array [] is the correct way to signal "no data".
    if (data === null || data === undefined) {
      const msg =
        `[EliteGrid] DataSource received ${data} as static data. ` +
        `Pass an empty array [] to show an empty grid, not null or undefined.`
      devError(msg)
      // devError throws in dev — only reached in production
      data = [] as unknown as TData[]
    }

    this.context.store.write('raw', {
      rows: data as unknown[],
      totalCount: data.length,
      loading: false,
      error: null,
    })

    // Notify engine that data is ready
    this.context.eventBus.emit(GridEvent.DATA_SET, {
      totalCount: data.length,
    })
  }

  // ── Async Load ────────────────────────────

  private async loadAsync(
    dataSource: IDataSource<TData>,
    params?: Partial<DataSourceParams>
  ): Promise<void> {
    // Increment request ID to track this specific request
    // If a newer request starts before this one finishes
    // the older response is discarded
    const requestId = ++this.currentRequestId

    // Set loading state
    this.context.store.write('raw', {
      loading: true,
      error: null,
    })

    // Notify loading started
    this.context.eventBus.emit(GridEvent.DATA_LOADING)

    try {
      // Build params from current store state
      const { currentPage, pageSize } = this.context.store.read('paginated')
      const { sortModel } = this.context.store.read('sorted')
      const { filterModel } = this.context.store.read('filtered')

      const fetchParams: DataSourceParams = {
        page: params?.page ?? currentPage,
        pageSize: params?.pageSize ?? pageSize,
        sortModel: params?.sortModel ?? sortModel,
        filterModel: params?.filterModel ?? filterModel,
      }

      // Fetch data
      const result = await dataSource.getRows(fetchParams)

      // Discard stale response if a newer request started
      if (requestId !== this.currentRequestId) {
        return
      }

      // Write result to store
      this.context.store.write('raw', {
        rows: result.rows as unknown[],
        totalCount: result.totalCount,
        loading: false,
        error: null,
      })

      // Notify engine that data is ready
      this.context.eventBus.emit(GridEvent.DATA_SET, {
        totalCount: result.totalCount,
      })
    } catch (error) {
      // Discard stale error if a newer request started
      if (requestId !== this.currentRequestId) {
        return
      }

      // Write error state to store
      this.context.store.write('raw', {
        loading: false,
        error: error instanceof Error ? error : new Error(String(error)),
      })

      // Notify engine of error
      this.context.eventBus.emit(GridEvent.DATA_LOAD_ERROR, {
        error,
      })
    }
  }

  // ── Handle Refresh ────────────────────────

  private handleRefresh = (): void => {
    this.load()
  }

  // ── Update Data ───────────────────────────
  // Called by Grid API when developer adds, updates, deletes rows

  setData(data: TData[]): void {
    this.config.data = data
    this.loadStatic(data)
  }

  addRow(row: TData, index?: number): void {
    const current = this.context.store.read('raw')
    const rows = [...current.rows] as TData[]

    if (index !== undefined) {
      rows.splice(index, 0, row)
    } else {
      rows.push(row)
    }

    this.context.store.write('raw', {
      rows: rows as unknown[],
      totalCount: rows.length,
    })

    this.context.eventBus.emit(GridEvent.ROW_ADDED, {
      row,
      index: index ?? rows.length - 1,
    })

    this.context.eventBus.emit(GridEvent.DATA_CHANGED, {
      type: 'add',
    })
  }

  // ── Extract Row ID ────────────────────────
  // Respects rowId config — mirrors RowModelPlugin.extractId()
  // Ensures updateRow/deleteRow find the right row regardless of id field name

  private extractRowId(row: unknown): string {
    const { rowId } = this.config
    if (typeof rowId === 'function') {
      return rowId(row as TData)
    }
    const field = rowId ?? 'id'
    const data = row as Record<string, unknown>
    if (data[field] !== undefined && data[field] !== null) {
      return String(data[field])
    }
    return ''
  }

  updateRow(rowId: string, changes: Partial<TData>): void {
    const current = this.context.store.read('raw')

    const updatedRows = current.rows.map((row) =>
      this.extractRowId(row) === rowId
        ? { ...(row as object), ...changes }
        : row
    )

    this.context.store.write('raw', {
      rows: updatedRows as unknown[],
    })

    this.context.eventBus.emit(GridEvent.ROW_UPDATED, {
      rowId,
      changes,
    })

    this.context.eventBus.emit(GridEvent.DATA_CHANGED, {
      type: 'update',
      rowId,
    })
  }

  deleteRow(rowId: string): void {
    const current = this.context.store.read('raw')

    const filteredRows = current.rows.filter(
      (row) => this.extractRowId(row) !== rowId
    )

    this.context.store.write('raw', {
      rows: filteredRows as unknown[],
      totalCount: filteredRows.length,
    })

    this.context.eventBus.emit(GridEvent.ROW_DELETED, {
      rowId,
    })

    this.context.eventBus.emit(GridEvent.DATA_CHANGED, {
      type: 'delete',
      rowId,
    })
  }

  // ── Destroy ───────────────────────────────

  destroy(): void {
    // Cancel any in-flight requests by invalidating request ID
    this.currentRequestId = Number.MAX_SAFE_INTEGER

    // Clean up event subscriptions
    this.cleanups.forEach((cleanup) => cleanup())
    this.cleanups = []
  }
}
