// ============================================
// @elitegrid/core — Row Model Plugin
// Manages row identity, storage, and ordering
// Owns nothing in Data Store directly
// Reads from raw namespace
// Provides O(1) row lookup to other plugins
// ============================================

import type { Plugin, PluginContext } from '../../kernel/index'
import { GridEvent } from '../../event-bus/events'
import type { RowId } from '../../types/index'
import { devWarn } from '../../utils/dev'

// ── Plugin ID ─────────────────────────────────

export const ROW_MODEL_PLUGIN_ID = 'row-model'

// ── Row Shape ─────────────────────────────────
// Every row must have an id field
// The id field name is configurable

export interface NormalizedRow {
  _id: RowId // internal stable ID
  _index: number // original load index
  _data: unknown // original row data
}

// ── Config ────────────────────────────────────

export interface RowModelConfig {
  // Which field in row data to use as ID
  // Default: 'id'
  rowId?: string | ((row: unknown) => RowId)
}

// ── Implementation ─────────────────────────────

export class RowModelPlugin implements Plugin {
  readonly id = ROW_MODEL_PLUGIN_ID

  private context!: PluginContext
  private config: RowModelConfig = {}

  // Core data structures
  // rowMap: O(1) lookup by ID
  private rowMap: Map<RowId, NormalizedRow> = new Map()

  // rowOrder: preserves display order
  private rowOrder: RowId[] = []

  // Reverse index: data object reference → engine ID
  // WeakMap so it doesn't prevent GC of discarded row data objects.
  // Updated in buildFromRows whenever the dataset is replaced.
  // Enables O(1) extractRowId() in SelectionPlugin instead of O(n) scan.
  private dataToId: WeakMap<object, RowId> = new WeakMap()

  // Auto-increment for generated IDs
  private autoIdCounter: number = 0

  // Cleanup functions
  private cleanups: Array<() => void> = []

  // ── Configure ─────────────────────────────

  configure(config: RowModelConfig): void {
    this.config = config
  }

  // ── Init ──────────────────────────────────

  init(context: PluginContext): void {
    this.context = context

    // When new data is loaded — rebuild row model
    this.cleanups.push(
      context.eventBus.on(GridEvent.DATA_SET, this.handleDataSet)
    )

    // When a row is added — add to model
    this.cleanups.push(
      context.eventBus.on(GridEvent.ROW_ADDED, this.handleRowAdded)
    )

    // When a row is updated — update in model
    this.cleanups.push(
      context.eventBus.on(GridEvent.ROW_UPDATED, this.handleRowUpdated)
    )

    // When a row is deleted — remove from model
    this.cleanups.push(
      context.eventBus.on(GridEvent.ROW_DELETED, this.handleRowDeleted)
    )

    // Build from any data already in store
    const { rows } = context.store.read('raw')
    if (rows.length > 0) {
      this.buildFromRows(rows)
    }
  }

  // ── Event Handlers ─────────────────────────

  private handleDataSet = (): void => {
    const { rows } = this.context.store.read('raw')
    this.buildFromRows(rows)
  }

  private handleRowAdded = (payload: { row: unknown; index: number }): void => {
    const normalized = this.normalizeRow(payload.row, payload.index)

    // Add to map
    this.rowMap.set(normalized._id, normalized)

    // Add to order at correct position
    if (payload.index >= this.rowOrder.length) {
      this.rowOrder.push(normalized._id)
    } else {
      this.rowOrder.splice(payload.index, 0, normalized._id)
    }
  }

  private handleRowUpdated = (payload: {
    rowId: RowId
    changes: unknown
  }): void => {
    const existing = this.rowMap.get(payload.rowId)
    if (!existing) return

    // Merge changes into existing row data
    this.rowMap.set(payload.rowId, {
      ...existing,
      _data: {
        ...(existing._data as object),
        ...(payload.changes as object),
      },
    })
  }

  private handleRowDeleted = (payload: { rowId: RowId }): void => {
    // Remove from map
    this.rowMap.delete(payload.rowId)

    // Remove from order
    const index = this.rowOrder.indexOf(payload.rowId)
    if (index !== -1) {
      this.rowOrder.splice(index, 1)
    }
  }

  // ── Build From Rows ────────────────────────

  private buildFromRows(rows: unknown[]): void {
    // Clear existing model
    this.rowMap.clear()
    this.rowOrder = []
    this.autoIdCounter = 0
    this.dataToId = new WeakMap()

    // Build new model from rows
    rows.forEach((row, index) => {
      const normalized = this.normalizeRow(row, index)

      // Duplicate ID detection — warn in dev, keep first occurrence
      if (this.rowMap.has(normalized._id)) {
        devWarn(
          `[EliteGrid] Duplicate row ID detected: "${normalized._id}". ` +
            `Each row must have a unique ID. The second occurrence (index ${index}) ` +
            `will be ignored. Check your data or rowId config.`
        )
        return // skip duplicate — first occurrence wins
      }

      this.rowMap.set(normalized._id, normalized)
      this.rowOrder.push(normalized._id)
      // Populate reverse index — only for object rows (WeakMap requires object keys)
      if (row !== null && typeof row === 'object') {
        this.dataToId.set(row as object, normalized._id)
      }
    })
  }

  // ── Normalize Row ──────────────────────────
  // Gives every row a stable internal ID

  private normalizeRow(row: unknown, index: number): NormalizedRow {
    const id = this.extractId(row)

    return {
      _id: id,
      _index: index,
      _data: row,
    }
  }

  // ── Extract ID ─────────────────────────────
  // Gets the ID from a row using configured field or function

  private extractId(row: unknown): RowId {
    const { rowId } = this.config

    // Custom function provided
    if (typeof rowId === 'function') {
      return rowId(row)
    }

    // Field name provided or default 'id'
    const field = rowId ?? 'id'
    const data = row as Record<string, unknown>

    if (data[field] !== undefined && data[field] !== null) {
      return String(data[field])
    }

    // No ID found — generate one
    return `__row_${++this.autoIdCounter}`
  }

  // ── Public API ─────────────────────────────
  // Used by other plugins and Grid API

  getRow(id: RowId): NormalizedRow | null {
    return this.rowMap.get(id) ?? null
  }

  // O(1) reverse lookup: given a raw data object, return its engine ID.
  // Uses the WeakMap reverse index populated in buildFromRows.
  // Returns null if the row is not in the current model.
  getIdForData(data: unknown): RowId | null {
    if (data === null || typeof data !== 'object') return null
    return this.dataToId.get(data as object) ?? null
  }

  getRowData(id: RowId): unknown | null {
    const row = this.rowMap.get(id)
    return row ? row._data : null
  }

  getAllRows(): NormalizedRow[] {
    return this.rowOrder.map((id) => this.rowMap.get(id)!)
  }

  getAllRowData(): unknown[] {
    return this.rowOrder.map((id) => this.rowMap.get(id)!._data)
  }

  getRowIndex(id: RowId): number {
    return this.rowOrder.indexOf(id)
  }

  getRowCount(): number {
    return this.rowMap.size
  }

  hasRow(id: RowId): boolean {
    return this.rowMap.has(id)
  }

  getRowIds(): RowId[] {
    return [...this.rowOrder]
  }

  // ── Destroy ───────────────────────────────

  destroy(): void {
    this.cleanups.forEach((cleanup) => cleanup())
    this.cleanups = []
    this.rowMap.clear()
    this.rowOrder = []
  }
}
