// ============================================
// @elitegrid/core — Column Model Plugin
// Manages column definitions and visual state
// Owns the 'columns' namespace in Data Store
// ============================================

import type { Plugin, PluginContext } from '../../kernel/index'
import { GridEvent } from '../../event-bus/events'
import type { ColumnId, PinPosition } from '../../types/index'
import type { ColumnDefinition } from '../../data-store/index'

// ── Plugin ID ─────────────────────────────────

export const COLUMN_MODEL_PLUGIN_ID = 'column-model'

// ── Column Input ──────────────────────────────
// What the adapter passes when defining columns

export interface ColumnInput {
  id?: ColumnId
  field: string
  header: string
  width?: number
  minWidth?: number
  maxWidth?: number
  flex?: number
  visible?: boolean
  pinned?: PinPosition
  resizable?: boolean
  sortable?: boolean
  filterable?: boolean
  editable?: boolean
}

// ── Config ────────────────────────────────────

export interface ColumnModelConfig {
  columns: ColumnInput[]
  defaultWidth?: number
  defaultMinWidth?: number
  defaultResizable?: boolean
  defaultSortable?: boolean
  defaultFilterable?: boolean
}

// ── Implementation ─────────────────────────────

export class ColumnModelPlugin implements Plugin {
  readonly id = COLUMN_MODEL_PLUGIN_ID

  private context!: PluginContext
  private config: ColumnModelConfig = { columns: [] }

  // Column storage
  // columnMap: O(1) lookup by ID
  private columnMap: Map<ColumnId, ColumnDefinition> = new Map()

  // Display order of column IDs
  private columnOrder: ColumnId[] = []

  // Auto-increment for generated column IDs
  private autoIdCounter: number = 0

  // Cleanup functions
  private cleanups: Array<() => void> = []

  // ── Configure ─────────────────────────────

  configure(config: ColumnModelConfig): void {
    this.config = config
  }

  // ── Init ──────────────────────────────────

  init(context: PluginContext): void {
    this.context = context

    // Build column model from config
    this.buildFromConfig()

    // Write initial state to store
    this.syncToStore()
  }

  // ── Build From Config ──────────────────────

  private buildFromConfig(): void {
    this.columnMap.clear()
    this.columnOrder = []
    this.autoIdCounter = 0

    const {
      columns,
      defaultWidth = 150,
      defaultMinWidth = 50,
      defaultResizable = true,
      defaultSortable = true,
      defaultFilterable = true,
    } = this.config

    columns.forEach((input) => {
      // Generate ID if not provided
      const id = input.id ?? this.generateId(input.field)

      const definition: ColumnDefinition = {
        id,
        field: input.field,
        header: input.header,
        width: input.flex != null ? undefined : (input.width ?? defaultWidth),
        minWidth: input.minWidth ?? defaultMinWidth,
        maxWidth: input.maxWidth,
        flex: input.flex,
        visible: input.visible ?? true,
        pinned: input.pinned ?? null,
        resizable: input.resizable ?? defaultResizable,
        sortable: input.sortable ?? defaultSortable,
        filterable: input.filterable ?? defaultFilterable,
        editable: input.editable ?? false,
      }

      this.columnMap.set(id, definition)
      this.columnOrder.push(id)
    })
  }

  // ── Sync To Store ──────────────────────────

  private syncToStore(): void {
    const definitions = this.columnOrder.map((id) => this.columnMap.get(id)!)

    const widths = new Map<ColumnId, number>()
    const visibility = new Map<ColumnId, boolean>()
    const pinState = new Map<ColumnId, PinPosition>()

    this.columnMap.forEach((col, id) => {
      widths.set(id, col.width ?? 150)
      visibility.set(id, col.visible)
      pinState.set(id, col.pinned)
    })

    this.context.store.write('columns', {
      definitions,
      order: [...this.columnOrder],
      widths,
      visibility,
      pinState,
    })
  }

  // ── Generate ID ────────────────────────────

  private generateId(field: string): ColumnId {
    // Use field name as ID if no conflicts
    if (!this.columnMap.has(field)) {
      return field
    }
    // Otherwise append counter
    return `${field}_${++this.autoIdCounter}`
  }

  // ── Public API ─────────────────────────────

  // Get single column definition
  getColumn(id: ColumnId): ColumnDefinition | null {
    return this.columnMap.get(id) ?? null
  }

  // Get all column definitions in display order
  getAllColumns(): ColumnDefinition[] {
    return this.columnOrder.map((id) => this.columnMap.get(id)!)
  }

  // Get only visible columns in display order
  getVisibleColumns(): ColumnDefinition[] {
    return this.columnOrder
      .map((id) => this.columnMap.get(id)!)
      .filter((col) => col.visible)
  }

  // Get pinned columns by position
  getPinnedColumns(position: 'left' | 'right'): ColumnDefinition[] {
    return this.columnOrder
      .map((id) => this.columnMap.get(id)!)
      .filter((col) => col.pinned === position && col.visible)
  }

  // Get unpinned visible columns
  getCenterColumns(): ColumnDefinition[] {
    return this.columnOrder
      .map((id) => this.columnMap.get(id)!)
      .filter((col) => col.pinned === null && col.visible)
  }

  // Get column count
  getColumnCount(): number {
    return this.columnMap.size
  }

  // Check if column exists
  hasColumn(id: ColumnId): boolean {
    return this.columnMap.has(id)
  }

  // ── Column Operations ──────────────────────

  setVisible(id: ColumnId, visible: boolean): void {
    const col = this.columnMap.get(id)
    if (!col) return

    this.columnMap.set(id, { ...col, visible })
    this.syncToStore()

    this.context.eventBus.emit(GridEvent.COLUMN_VISIBILITY_CHANGED, {
      columnId: id,
      visible,
    })
  }

  setWidth(columnId: ColumnId, width: number, containerWidth?: number): void {
    const col = this.columnMap.get(columnId)
    if (!col) return

    // ── AG Grid behavior ──────────────────────────────────────────────
    // Before freezing the resized column, freeze ALL currently-flex
    // columns at their current pixel width. This prevents them from
    // recalculating (and shrinking) when remainingWidth changes.
    //
    // The adapter passes containerWidth so we can compute current flex
    // widths. If not provided, we skip freezing (backward compat).
    if (containerWidth != null && containerWidth > 0) {
      const { definitions } = this.context.store.read('columns')

      // Calculate current pixel widths for all flex columns
      const fixedTotal = definitions
        .filter(
          (d) => d.visible !== false && d.width != null && d.id !== columnId
        )
        .reduce((sum, d) => sum + (d.width ?? 0), 0)

      const flexCols = definitions.filter(
        (d) => d.visible !== false && d.width == null && d.id !== columnId
      )

      if (flexCols.length > 0) {
        const remaining = Math.max(0, containerWidth - fixedTotal)
        const totalFlex = flexCols.reduce((sum, d) => sum + (d.flex ?? 1), 0)

        flexCols.forEach((d) => {
          const calculated = ((d.flex ?? 1) / totalFlex) * remaining
          const frozenWidth = Math.max(d.minWidth ?? 50, Math.floor(calculated))
          const frozen = { ...d, width: frozenWidth }
          this.columnMap.set(d.id, frozen)
        })
      }
    }
    // ─────────────────────────────────────────────────────────────────

    // Now freeze the resized column itself — clamp to min/max constraints
    const clampedWidth = Math.min(
      col.maxWidth ?? Infinity,
      Math.max(col.minWidth ?? 0, width)
    )
    const updated = { ...col, width: clampedWidth }
    this.columnMap.set(columnId, updated)
    this.syncToStore()

    this.context.eventBus.emit(GridEvent.COLUMN_RESIZED, {
      columnId,
      width: clampedWidth,
    })
  }

  setPinned(id: ColumnId, position: PinPosition): void {
    const col = this.columnMap.get(id)
    if (!col) return

    this.columnMap.set(id, { ...col, pinned: position })
    this.syncToStore()

    this.context.eventBus.emit(GridEvent.COLUMN_PINNED_CHANGED, {
      columnId: id,
      pinned: position,
    })
  }

  moveColumn(id: ColumnId, toIndex: number): void {
    const fromIndex = this.columnOrder.indexOf(id)
    if (fromIndex === -1) return

    // Clamp toIndex within bounds
    const clampedIndex = Math.min(
      Math.max(0, toIndex),
      this.columnOrder.length - 1
    )

    // Remove from current position
    this.columnOrder.splice(fromIndex, 1)

    // Insert at new position
    this.columnOrder.splice(clampedIndex, 0, id)

    this.syncToStore()

    this.context.eventBus.emit(GridEvent.COLUMN_REORDERED, {
      columnIds: [...this.columnOrder],
    })
  }

  // Get current column state for save/restore
  getColumnState() {
    return this.columnOrder.map((id, index) => {
      const col = this.columnMap.get(id)!
      return {
        columnId: id,
        width: col.width ?? 150,
        visible: col.visible,
        pinned: col.pinned,
        index,
      }
    })
  }

  // Apply saved column state
  applyColumnState(
    state: Array<{
      columnId: ColumnId
      width?: number
      visible?: boolean
      pinned?: PinPosition
      index?: number
    }>
  ): void {
    // Apply each state entry
    state.forEach(({ columnId, width, visible, pinned }) => {
      const col = this.columnMap.get(columnId)
      if (!col) return

      this.columnMap.set(columnId, {
        ...col,
        width: width ?? col.width,
        visible: visible ?? col.visible,
        pinned: pinned !== undefined ? pinned : col.pinned,
      })
    })

    // Reorder if indices provided
    const withIndex = state
      .filter((s) => s.index !== undefined)
      .sort((a, b) => (a.index ?? 0) - (b.index ?? 0))

    if (withIndex.length > 0) {
      this.columnOrder = withIndex.map((s) => s.columnId)
    }

    this.syncToStore()
  }

  // ── Destroy ───────────────────────────────

  destroy(): void {
    this.cleanups.forEach((cleanup) => cleanup())
    this.cleanups = []
    this.columnMap.clear()
    this.columnOrder = []
  }
}
