// ============================================
// @elitegrid/vue — GridBody
// The scroll container — virtualises visible rows.
//
// IDEOLOGY:
// The viewport plugin in core computes which rows are currently
// visible based on scrollTop / containerHeight. We render those
// rows positioned via `transform: translateY(offsetTop)` inside
// a spacer div sized to `totalHeight`. That gives us native
// browser scrolling without putting every row in the DOM.
//
// Three things attached to the scroll container:
//   1. useGrid()        — ResizeObserver + scroll listener
//   2. useFocusManager  — DOM .focus() on FOCUS_CHANGED
//   3. Keyboard handler — arrow keys, Tab, Enter â†’ engine events
//
// Mirror of react/src/components/GridBody.tsx
// ============================================

import {
  defineComponent,
  h,
  ref,
  computed,
  onMounted,
  onBeforeUnmount,
} from 'vue'
import { GridEvent } from '@elitegrid/core'
import { useGridContext } from '../context/GridContext'
import { useViewportState, useColumnsState } from '../composables/useGridStates'
import { useGrid } from '../composables/useGrid'
import { useFocusManager } from '../composables/useFocusManager'
import { GridRow } from './GridRow'
import { GridOverlay } from './GridOverlay'
import { GridHeader } from './GridHeader'
import { calculateColumnWidths } from '../utils/columnWidths'

export const GridBody = defineComponent({
  name: 'GridBody',
  props: {},
  setup() {
    const grid = useGridContext()
    const { containerRef } = useGrid(grid)
    useFocusManager(grid, containerRef)

    const viewport = useViewportState(grid)
    const columns = useColumnsState(grid)

    // Loading flag — drives the shimmer skeleton. hasAttemptedLoad tracks
    // whether any data load has started; without this, static data shows the
    // shimmer for one render before the viewport plugin computes visibleRows.
    const hasRawData = grid.kernel.store.read('raw').rows.length > 0
    const isLoading = ref(
      grid.kernel.store.read('viewport').visibleRows.length === 0 &&
        !hasRawData
    )

    // ── Subscriptions ──────────────────────────────
    let unsubViewport: (() => void) | null = null
    let unsubDataLoading: (() => void) | null = null
    let unsubSort: (() => void) | null = null
    let unsubPage: (() => void) | null = null
    let unsubFilter: (() => void) | null = null

    onMounted(() => {
      // Loading shimmer dismissal — fires on first non-empty viewport tick
      unsubViewport = grid.kernel.eventBus.on(
        GridEvent.VIEWPORT_CHANGED,
        () => {
          const { visibleRows } = grid.kernel.store.read('viewport')
          if (visibleRows.length > 0) isLoading.value = false
        }
      )
      unsubDataLoading = grid.kernel.eventBus.on(GridEvent.DATA_LOADING, () => {
        isLoading.value = true
      })

      // Header is now rendered sticky inside this scroll container (see GridHeader).
      // Horizontal scroll moves header + rows as a single native unit — no JS sync.

      // Reset scroll on sort/filter/page change so user starts at top
      const resetScrollTop = () => {
        if (containerRef.value) containerRef.value.scrollTop = 0
      }
      unsubSort = grid.kernel.eventBus.on(
        GridEvent.SORT_COMPLETED,
        resetScrollTop
      )
      unsubPage = grid.kernel.eventBus.on(
        GridEvent.PAGE_CHANGED,
        resetScrollTop
      )
      unsubFilter = grid.kernel.eventBus.on(
        GridEvent.FILTER_COMPLETED,
        resetScrollTop
      )
    })

    onBeforeUnmount(() => {
      unsubViewport?.()
      unsubDataLoading?.()
      unsubSort?.()
      unsubPage?.()
      unsubFilter?.()
    })

    // Stable column-widths Map (only rebuilds when defs/options/width change)
    const columnWidths = computed(() =>
      calculateColumnWidths(
        columns.value.definitions,
        grid.options.columns,
        viewport.value.containerWidth
      )
    )

    // Lookup Maps — saves O(n) find() in every cell render
    const columnDefMap = computed(
      () => new Map(columns.value.definitions.map((d) => [d.id, d]))
    )
    const columnOptionsMap = computed(
      () => new Map(grid.options.columns.map((c) => [c.field as string, c]))
    )

    // ── Keyboard navigation handler ─────────────────
    const handleKeyDown = (e: KeyboardEvent) => {
      const { isEditing: editing } = grid.kernel.store.read('editing')
      if (editing) return // editor owns keys when open

      const keyMap: Record<
        string,
        { direction: string; editableOnly?: boolean }
      > = {
        ArrowUp: { direction: 'up' },
        ArrowDown: { direction: 'down' },
        ArrowLeft: { direction: 'left' },
        ArrowRight: { direction: 'right' },
        Tab: { direction: e.shiftKey ? 'prev' : 'next' },
        Home: { direction: e.ctrlKey ? 'first' : 'rowStart' },
        End: { direction: e.ctrlKey ? 'last' : 'rowEnd' },
        Enter: { direction: 'none' },
      }
      const mapping = keyMap[e.key]
      if (!mapping) return
      e.preventDefault()

      if (e.key === 'Enter') {
        const { focusedCell } = grid.kernel.store.read('focus')
        if (focusedCell) {
          grid.kernel.eventBus.emit(GridEvent.EDIT_START_REQUESTED, {
            cell: focusedCell,
          })
        }
        return
      }

      grid.kernel.eventBus.emit(GridEvent.FOCUS_MOVE_REQUESTED, {
        direction: mapping.direction,
        editableOnly: false,
      })
    }

    return () => {
      const {
        visibleRows,
        visibleColumnIds,
        offsetTop,
        totalHeight,
        rowHeight,
        totalWidth,
        startRowIndex,
      } = viewport.value

      // The engine's totalWidth covers only data columns. The checkbox column
      // (48px) is rendered outside the engine model. The spacer's minWidth must
      // include the checkbox so body.scrollWidth == header.scrollWidth — without
      // this, the header's last column icons are clipped when scrolled to the
      // far right because the header can scroll 48px further than the body.
      const showCheckboxes =
        grid.options.selection?.mode !== 'none' &&
        (grid.options.selection?.showCheckboxes ?? true)
      const scrollableWidth = totalWidth + (showCheckboxes ? 48 : 0)

      const skeletonRowCount = Math.ceil(
        (containerRef.value?.clientHeight ?? 400) / rowHeight
      )

      // ── Loading shimmer (skeleton) ───────────────
      const shimmer = isLoading.value
        ? h(
            'div',
            {
              'aria-hidden': 'true',
              style: {
                position: 'absolute',
                top: 0,
                left: 0,
                right: 0,
                bottom: 0,
                backgroundColor: 'var(--eg-row-bg)',
                display: 'flex',
                flexDirection: 'column',
                overflow: 'hidden',
                // zIndex 1 keeps shimmer below the sticky header (zIndex 2)
                // so column names stay visible during loading.
                zIndex: 1,
              },
            },
            Array.from({ length: skeletonRowCount }).map((_, i) =>
              h(
                'div',
                {
                  key: i,
                  style: {
                    height: `${rowHeight}px`,
                    minHeight: `${rowHeight}px`,
                    display: 'flex',
                    alignItems: 'center',
                    borderBottom: '1px solid var(--eg-row-border)',
                    backgroundColor: i % 2 === 0 ? 'var(--eg-row-striped-bg)' : 'var(--eg-row-bg)',
                    boxSizing: 'border-box',
                    flexShrink: 0,
                  },
                },
                visibleColumnIds.map((colId) => {
                  const colWidth = columnWidths.value.get(colId) ?? 150
                  return h(
                    'div',
                    {
                      key: colId,
                      style: {
                        width: `${colWidth}px`,
                        minWidth: `${colWidth}px`,
                        maxWidth: `${colWidth}px`,
                        height: '100%',
                        display: 'flex',
                        alignItems: 'center',
                        padding: '0 12px',
                        boxSizing: 'border-box',
                        flexShrink: 0,
                      },
                    },
                    [
                      h('div', {
                        style: {
                          width: '100%',
                          height: '12px',
                          borderRadius: '6px',
                          background:
                            'linear-gradient(90deg, var(--eg-skeleton-base) 25%, var(--eg-skeleton-highlight) 50%, var(--eg-skeleton-base) 75%)',
                          backgroundSize: '200% 100%',
                          animation: 'yg-shimmer 1.2s infinite',
                        },
                      }),
                    ]
                  )
                })
              )
            )
          )
        : null

      // ── Virtual rows ─────────────────────────────
      // Use the configured rowId field — never hardcode 'id'.
      // options.rowId can be a string key or a function; the render paths
      // support the string form (function rowId falls back to 'id', matching
      // the React adapter).
      const rowIdField =
        typeof grid.options.rowId === 'string' ? grid.options.rowId : 'id'
      const rows = visibleRows.map((row, index) => {
        const rawRow = row as Record<string, unknown>
        const rowId = String(
          rawRow[rowIdField] ?? `__row_${startRowIndex + index}`
        )
        return h(GridRow, {
          key: rowId,
          rowId,
          row: rawRow,
          rowIndex: startRowIndex + index,
          rowHeight,
          visibleColumnIds,
          columnWidths: columnWidths.value,
          columnDefMap: columnDefMap.value,
          columnOptionsMap: columnOptionsMap.value,
        })
      })

      return h(
        'div',
        {
          ref: containerRef,
          class: 'yg-body',
          // Outer Grid wrapper already has role="grid"; the scroll
          // container must not duplicate it. Use presentation so AT
          // doesn't see two nested grids.
          role: 'presentation',
          tabindex: 0,
          onKeydown: handleKeyDown,
          style: {
            flex: 1,
            // Always reserve scrollbar space — keeps clientWidth stable
            // and prevents column widths from jumping when content fits.
            overflowY: 'scroll',
            overflowX: 'auto',
            position: 'relative',
            WebkitOverflowScrolling: 'touch',
            outline: 'none',
          },
        },
        [
          // Sticky header — inside the unified scroll container so horizontal
          // scroll moves header and rows as a single native unit. Zero JS sync.
          h(GridHeader),
          shimmer,
          // Spacer creates the full scrollable area
          h(
            'div',
            {
              style: {
                height: `${totalHeight}px`,
                minWidth: `${scrollableWidth}px`,
                position: 'relative',
                pointerEvents: 'none',
                // contain:strict tells the browser this subtree is
                // self-contained — paint and layout isolation for
                // virtualised content (prevents full-container repaints).
                contain: 'strict',
              },
            },
            [
              // Translated wrapper positions visible rows at offsetTop
              h(
                'div',
                {
                  style: {
                    position: 'absolute',
                    top: 0,
                    left: 0,
                    minWidth: `${scrollableWidth}px`,
                    transform: `translateY(${offsetTop}px)`,
                    pointerEvents: 'auto',
                    // Promotes to its own GPU compositor layer so translateY
                    // changes never trigger a repaint of the scroll background.
                    willChange: 'transform',
                  },
                },
                rows
              ),
            ]
          ),
          h(GridOverlay),
          // Keyframes for the shimmer animation
          h(
            'style',
            null,
            `@keyframes yg-shimmer { 0% { background-position: 200% 0; } 100% { background-position: -200% 0; } }`
          ),
        ]
      )
    }
  },
})
