// ============================================
// @elitegrid/vue — GridRow
// Renders one row of cells.
//
// IDEOLOGY:
// Single responsibility: lay out cells horizontally for one row
// of data. Selection state for THIS row only is subscribed via
// useCellSelected — without this, every row would re-render on
// every selection change (O(n) renders for a single click).
//
// Row click handler emits ROW_CLICK_SELECTION only when the click
// falls on row padding (cells stop propagation themselves).
//
// Mirror of react/src/components/GridRow.tsx
// ============================================

import { defineComponent, h, toRef, type PropType } from 'vue'
import { GridEvent } from '@elitegrid/core'
import type { ColumnId } from '@elitegrid/core'
import type { ColumnDef } from '../create-grid'
import { useGridContext } from '../context/GridContext'
import { useCellSelected } from '../composables/useGridStates'
import { GridCell } from './GridCell'

export const GridRow = defineComponent({
  name: 'GridRow',
  props: {
    rowId: { type: String, required: true },
    row: {
      type: Object as PropType<Record<string, unknown>>,
      required: true,
    },
    rowIndex: { type: Number, required: true },
    rowHeight: { type: Number, required: true },
    visibleColumnIds: {
      type: Array as PropType<ColumnId[]>,
      required: true,
    },
    columnWidths: {
      type: Object as PropType<Map<string, number>>,
      required: true,
    },
    columnDefMap: {
      type: Object as PropType<Map<string, unknown>>,
      required: true,
    },
    columnOptionsMap: {
      type: Object as PropType<Map<string, ColumnDef>>,
      required: true,
    },
  },
  setup(props) {
    const grid = useGridContext()
    // Per-row derived selector — only this row re-renders when its
    // own selection state flips, not the entire viewport.
    // toRef satisfies vue/no-setup-props-reactivity-loss; rowId is stable
    // per mounted row (parent uses :key="rowId" so rekeys on ID change).
    const rowIdRef = toRef(props, 'rowId')
    const isSelected = useCellSelected(grid, rowIdRef.value)

    return () => {
      const { options } = grid
      const selectionMode = options.selection?.mode ?? 'none'
      const selectOnRowClick = options.selection?.selectOnRowClick ?? true
      const checkboxOnly = options.selection?.checkboxOnly ?? false
      const showCheckboxes =
        selectionMode !== 'none' && (options.selection?.showCheckboxes ?? true)

      const isEven = props.rowIndex % 2 === 0
      const showStriping = options.appearance?.rowStriping ?? true

      // ── Row-level click — fires only for non-cell areas (padding etc) ──
      const handleRowClick = (e: MouseEvent) => {
        if (selectionMode !== 'none' && selectOnRowClick && !checkboxOnly) {
          grid.kernel.eventBus.emit(GridEvent.ROW_CLICK_SELECTION, {
            rowId: props.rowId,
            shiftKey: e.shiftKey,
            ctrlKey: e.ctrlKey,
            metaKey: e.metaKey,
          })
        }
        options.events?.onRowClick?.(props.row as unknown, e)
      }

      const handleRowDblClick = (e: MouseEvent) => {
        options.events?.onRowDoubleClick?.(props.row as unknown, e)
      }

      // ── Checkbox cell ─────────────────────────────
      const checkboxCell = showCheckboxes
        ? h(
            'div',
            {
              class: 'yg-cell yg-cell--checkbox',
              role: 'gridcell',
              style: {
                width: '48px',
                minWidth: '48px',
                maxWidth: '48px',
                height: '100%',
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'center',
                flexShrink: 0,
                boxSizing: 'border-box',
              },
              onClick: (e: MouseEvent) => e.stopPropagation(),
            },
            [
              h('input', {
                type: 'checkbox',
                'aria-label': `Select row ${props.rowIndex + 1}`,
                checked: isSelected.value,
                onChange: (e: Event) => {
                  grid.kernel.eventBus.emit(GridEvent.CHECKBOX_ROW_CHANGED, {
                    rowId: props.rowId,
                    checked: (e.target as HTMLInputElement).checked,
                  })
                },
                style: {
                  cursor: 'pointer',
                  width: '16px',
                  height: '16px',
                  accentColor: 'var(--eg-primary)',
                },
              }),
            ]
          )
        : null

      // ── Cells ────────────────────────────────────
      const cells = props.visibleColumnIds.map((columnId, columnIndex) =>
        h(GridCell, {
          key: columnId,
          rowId: props.rowId,
          columnId,
          columnIndex,
          rowIndex: props.rowIndex,
          // Pass full row — CellValuePlugin extracts the column field internally.
          // Same idiom as React adapter; allows formatters with full row context.
          getCellValue: () => props.row,
          columnWidths: props.columnWidths,
          columnDefMap: props.columnDefMap,
          columnOptionsMap: props.columnOptionsMap,
        })
      )

      return h(
        'div',
        {
          class: 'yg-row',
          role: 'row',
          'aria-rowindex': props.rowIndex + 1,
          'aria-selected':
            selectionMode !== 'none' ? isSelected.value : undefined,
          onClick: handleRowClick,
          onDblclick: handleRowDblClick,
          style: {
            height: `${props.rowHeight}px`,
            minHeight: `${props.rowHeight}px`,
            maxHeight: `${props.rowHeight}px`,
            display: 'flex',
            flexDirection: 'row',
            alignItems: 'center',
            boxSizing: 'border-box',
            backgroundColor: isSelected.value
              ? 'var(--eg-row-selected-bg)'
              : showStriping && isEven
                ? 'var(--eg-row-striped-bg)'
                : 'var(--eg-row-bg)',
            borderBottom: isSelected.value
              ? 'var(--eg-row-selected-border)'
              : 'var(--eg-row-border)',
            cursor:
              selectionMode !== 'none' || options.events?.onRowClick
                ? 'pointer'
                : 'default',
            outline: isSelected.value
              ? '1px solid var(--eg-row-selected-outline, transparent)'
              : undefined,
            userSelect: 'none',
          },
        },
        [checkboxCell, ...cells]
      )
    }
  },
})
