// ============================================
// @elitegrid/vue — GridPagination
// Pagination control bar below the grid.
//
// IDEOLOGY:
// Pure presentation + plugin method calls. The pagination plugin
// owns the state — this component subscribes via usePaginationState
// and dispatches user intent (setPage, setPageSize) back to it.
//
// Responsibilities:
//   1. Show "Showing X–Y of N" row count
//   2. Page size selector dropdown
//   3. First / Prev / Next / Last navigation
//   4. Page number buttons with ellipsis (1 â€¦ 4 5 6 â€¦ 20)
//
// Mirror of react/src/components/GridPagination.tsx
// ============================================

import { defineComponent, h, computed } from 'vue'
import { useGridContext } from '../context/GridContext'
import { usePaginationState } from '../composables/useGridStates'

const buttonBase = {
  display: 'inline-flex',
  alignItems: 'center',
  justifyContent: 'center',
  height: '32px',
  minWidth: '32px',
  padding: '0 8px',
  border: '1px solid var(--eg-border)',
  borderRadius: '6px',
  backgroundColor: 'var(--eg-btn-bg)',
  color: 'var(--eg-btn-text)',
  fontSize: '0.875rem',
  cursor: 'pointer',
  userSelect: 'none' as const,
  transition: 'background-color 0.15s, border-color 0.15s',
  fontFamily: 'inherit',
}

const activeButtonStyle = {
  ...buttonBase,
  backgroundColor: 'var(--eg-primary)',
  borderColor: 'var(--eg-primary)',
  color: 'var(--eg-primary-text)',
  fontWeight: 600,
}

const disabledButtonStyle = {
  ...buttonBase,
  opacity: 0.4,
  cursor: 'not-allowed',
}

export const GridPagination = defineComponent({
  name: 'GridPagination',
  setup() {
    const grid = useGridContext()
    const pagination = usePaginationState(grid)
    const { options } = grid

    // Memoised page-number array — recomputes only when currentPage / totalPages change.
    // Shows "1 â€¦ 4 5 6 â€¦ 20" — always first, last, current, Â±1 sibling.
    const pageNumbers = computed<Array<number | '...'>>(() => {
      const { currentPage, totalPages } = pagination.value
      if (totalPages <= 7) {
        return Array.from({ length: totalPages }, (_, i) => i + 1)
      }
      const pages: Array<number | '...'> = []
      const showLeftEllipsis = currentPage > 3
      const showRightEllipsis = currentPage < totalPages - 2
      pages.push(1)
      if (showLeftEllipsis) pages.push('...')
      const start = Math.max(2, currentPage - 1)
      const end = Math.min(totalPages - 1, currentPage + 1)
      for (let i = start; i <= end; i++) pages.push(i)
      if (showRightEllipsis) pages.push('...')
      pages.push(totalPages)
      return pages
    })

    // onPageChange fires from the create-grid PAGE_CHANGED / PAGE_SIZE_CHANGED
    // listeners (the plugin methods below emit those events) — not here — so
    // the callback isn't double-called.
    const handlePageChange = (page: number) => {
      grid.plugins.pagination.setPage(page)
    }

    const handlePageSizeChange = (e: Event) => {
      const newSize = Number((e.target as HTMLSelectElement).value)
      grid.plugins.pagination.setPageSize(newSize)
    }

    return () => {
      if (!options.pagination?.enabled) return null

      const {
        currentPage,
        pageSize,
        totalPages,
        totalRows,
        startRow,
        endRow,
        hasNextPage,
        hasPreviousPage,
      } = pagination.value

      const pageSizeOptions = options.pagination?.pageSizeOptions ?? [
        10, 25, 50, 100,
      ]
      const showPageSizeSelector =
        options.pagination?.showPageSizeSelector ?? true
      const showRowCount = options.pagination?.showRowCount ?? true
      const showPageNumbers = options.pagination?.showPageNumbers ?? true

      // ── Left side: row count + page size selector ─────────────
      const leftBlock = h(
        'div',
        { style: { display: 'flex', alignItems: 'center', gap: '12px' } },
        [
          showRowCount && totalRows > 0
            ? h(
                'span',
                {
                  style: {
                    fontSize: '0.875rem',
                    color: 'var(--eg-muted-text)',
                    whiteSpace: 'nowrap',
                  },
                },
                [
                  'Showing ',
                  h(
                    'strong',
                    { style: { color: 'var(--eg-text)' } },
                    `${startRow}–${endRow}`
                  ),
                  ' of ',
                  h(
                    'strong',
                    { style: { color: 'var(--eg-text)' } },
                    totalRows.toLocaleString()
                  ),
                ]
              )
            : null,
          showPageSizeSelector
            ? h(
                'div',
                {
                  style: {
                    display: 'flex',
                    alignItems: 'center',
                    gap: '6px',
                  },
                },
                [
                  h(
                    'span',
                    {
                      style: {
                        fontSize: '0.875rem',
                        color: 'var(--eg-muted-text)',
                        whiteSpace: 'nowrap',
                      },
                    },
                    'Rows per page'
                  ),
                  h(
                    'select',
                    {
                      value: String(pageSize),
                      onChange: handlePageSizeChange,
                      style: {
                        height: '32px',
                        padding: '0 8px',
                        border: '1px solid var(--eg-border)',
                        borderRadius: '6px',
                        backgroundColor: 'var(--eg-btn-bg)',
                        color: 'var(--eg-btn-text)',
                        fontSize: '0.875rem',
                        cursor: 'pointer',
                        fontFamily: 'inherit',
                      },
                    },
                    pageSizeOptions.map((size) =>
                      h('option', { key: size, value: size }, String(size))
                    )
                  ),
                ]
              )
            : null,
        ]
      )

      // ── Right side: page navigation buttons ─────────────────
      const navButton = (
        key: string,
        label: string,
        ariaLabel: string,
        disabled: boolean,
        onClick: () => void,
        style = buttonBase
      ) =>
        h(
          'button',
          {
            key,
            onClick: disabled ? undefined : onClick,
            disabled,
            style: disabled ? disabledButtonStyle : style,
            title: ariaLabel,
            'aria-label': ariaLabel,
          },
          label
        )

      const rightBlock = h(
        'div',
        { style: { display: 'flex', alignItems: 'center', gap: '4px' } },
        [
          navButton('first', '«', 'First page', !hasPreviousPage, () =>
            handlePageChange(1)
          ),
          navButton('prev', '‹', 'Previous page', !hasPreviousPage, () =>
            handlePageChange(currentPage - 1)
          ),
          showPageNumbers
            ? pageNumbers.value.map((page, index) =>
                page === '...'
                  ? h(
                      'span',
                      {
                        key: `ellipsis-${index}`,
                        style: {
                          padding: '0 4px',
                          color: 'var(--eg-muted-text)',
                          fontSize: '0.875rem',
                          userSelect: 'none',
                        },
                      },
                      '...'
                    )
                  : h(
                      'button',
                      {
                        key: page,
                        onClick: () => handlePageChange(page as number),
                        style:
                          page === currentPage ? activeButtonStyle : buttonBase,
                        'aria-label': `Page ${page}`,
                        'aria-current':
                          page === currentPage ? 'page' : undefined,
                      },
                      String(page)
                    )
              )
            : null,
          navButton('next', '›', 'Next page', !hasNextPage, () =>
            handlePageChange(currentPage + 1)
          ),
          navButton('last', '»', 'Last page', !hasNextPage, () =>
            handlePageChange(totalPages)
          ),
        ]
      )

      return h(
        'div',
        {
          class: 'yg-pagination',
          style: {
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'space-between',
            padding: '8px 12px',
            borderTop: 'var(--eg-header-border)',
            backgroundColor: 'var(--eg-header-bg)',
            flexShrink: 0,
            gap: '8px',
            flexWrap: 'wrap',
          },
        },
        [leftBlock, rightBlock]
      )
    }
  },
})
