// ============================================
// @elitegrid/vue — GridContext
// Vue equivalent of React's createContext / useContext.
//
// IDEOLOGY:
// One GridInstance is created outside the component tree.
// Every grid sub-component (header, body, row, cell) needs
// access to that same instance. Passing it through props at
// every level is noisy and brittle.
//
// Vue's solution is provide() / inject() — a key/value channel
// that propagates down the component tree. The root <Grid>
// component calls provide(GridInstanceKey, instance), and every
// descendant calls useGridContext() to retrieve it.
//
// This file owns only:
//   1. The InjectionKey symbol (type-safe channel identity)
//   2. The useGridContext composable (descendant accessor)
// ============================================

import { inject, type InjectionKey } from 'vue'
import type { GridInstance } from '../create-grid'

// ── Injection key ──────────────────────────────
// Symbols give every grid instance a unique, type-safe key.
// `InjectionKey<T>` is Vue's way of binding a key to a value type
// so `inject(GridInstanceKey)` returns `GridInstance | undefined`
// without manual casts.
//
// Exported so advanced consumers can `provide(GridInstanceKey, …)`
// manually (e.g. headless mode with a custom shell component).

export const GridInstanceKey: InjectionKey<GridInstance<unknown>> =
  Symbol('GridInstance')

// ── useGridContext ─────────────────────────────
// Internal composable used by every grid sub-component.
//
// Throws a clear error if used outside <Grid> — surfacing the
// configuration bug at runtime rather than silently rendering
// nothing or crashing in a deeper call.

export function useGridContext<TData = unknown>(): GridInstance<TData> {
  const instance = inject(GridInstanceKey)

  if (!instance) {
    throw new Error(
      '[EliteGrid] Grid components must be used inside <Grid>. ' +
        'Make sure the parent component renders <Grid :grid="grid" /> ' +
        'and that you are not using grid composables outside its tree.'
    )
  }

  return instance as GridInstance<TData>
}
