// ============================================
// @elitegrid/vue — GridOverlay
// Renders error and empty state overlays.
//
// IDEOLOGY:
// Loading state is rendered as a shimmer skeleton in GridBody.
// This overlay only handles the two terminal states the user
// can see *instead* of the loading skeleton:
//   • Error  — pipeline failed, show the message.
//   • Empty  — pipeline succeeded but produced zero rows.
//
// Priority of presentation, from most-specific to most-generic:
//   1. Custom component (full control)
//   2. Simple props (title, description, icon)
//   3. Default built-in UI
//
// Mirror of react/src/components/GridOverlay.tsx
// ============================================

import { defineComponent, h, computed } from 'vue'
import { useGridContext } from '../context/GridContext'
import {
  useRawState,
  usePaginationState,
} from '../composables/useGridStates'

const overlayStyle = {
  position: 'absolute' as const,
  top: 0,
  left: 0,
  right: 0,
  bottom: 0,
  display: 'flex',
  flexDirection: 'column' as const,
  alignItems: 'center',
  justifyContent: 'center',
  backgroundColor: 'var(--eg-overlay-bg, rgba(255,255,255,0.9))',
  zIndex: 5,
  gap: '12px',
}

const iconBubble = (emoji: string, bg = 'var(--eg-empty-icon-bg)') =>
  h(
    'div',
    {
      style: {
        width: '56px',
        height: '56px',
        borderRadius: '50%',
        backgroundColor: bg,
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        fontSize: '1.5rem',
      },
    },
    emoji
  )

const messageBlock = (title: string, description: string) =>
  h('div', { style: { textAlign: 'center' } }, [
    h(
      'p',
      {
        style: {
          margin: 0,
          fontSize: '0.9375rem',
          fontWeight: 600,
          color: 'var(--eg-text)',
        },
      },
      title
    ),
    h(
      'p',
      {
        style: {
          margin: '4px 0 0',
          fontSize: '0.8125rem',
          color: 'var(--eg-muted-text)',
        },
      },
      description
    ),
  ])

export const GridOverlay = defineComponent({
  name: 'GridOverlay',
  setup() {
    const grid = useGridContext()
    const raw = useRawState(grid)
    // Subscribe to `paginated` too. Filtering/sorting/paging mutate the
    // paginated namespace WITHOUT touching raw, so subscribing to raw alone
    // means the overlay never re-evaluates when a filter empties the grid
    // (Vue's fine-grained reactivity won't re-render this component unless one
    // of its own reactive deps changes). This is what made the filtered-empty
    // state never appear.
    const paginated = usePaginationState(grid)

    const display = computed(() => {
      const { loading, error, rows } = raw.value
      const { rows: paginatedRows } = paginated.value
      const appearance = grid.options.appearance

      const hasSourceData = rows.length > 0
      const isFilteredEmpty = hasSourceData && paginatedRows.length === 0

      return {
        loading,
        error,
        paginatedRows,
        isFilteredEmpty,
        appearance,
      }
    })

    return () => {
      const { loading, error, paginatedRows, isFilteredEmpty, appearance } =
        display.value

      // Custom loading component — default loading is the shimmer in GridBody
      if (loading && appearance?.loadingComponent) {
        return h(
          'div',
          { style: overlayStyle, class: 'yg-overlay yg-overlay--loading' },
          [h(appearance.loadingComponent)]
        )
      }

      // Error state
      if (error) {
        if (appearance?.errorComponent) {
          return h(
            'div',
            { style: overlayStyle, class: 'yg-overlay yg-overlay--error' },
            [h(appearance.errorComponent, { error })]
          )
        }
        return h(
          'div',
          {
            class: 'yg-overlay yg-overlay--error',
            style: overlayStyle,
            role: 'alert',
            'aria-live': 'assertive',
          },
          [
            iconBubble('⚠️', 'var(--eg-error-bg)'),
            h('div', { style: { textAlign: 'center' } }, [
              h(
                'p',
                {
                  style: {
                    margin: 0,
                    fontSize: '0.875rem',
                    fontWeight: 600,
                    color: 'var(--eg-error)',
                  },
                },
                'Failed to load data'
              ),
              h(
                'p',
                {
                  style: {
                    margin: '4px 0 0',
                    fontSize: '0.8rem',
                    color: 'var(--eg-muted-text)',
                  },
                },
                error.message
              ),
            ]),
          ]
        )
      }

      // Don't show empty state while loading — shimmer covers it
      if (loading) return null
      if (paginatedRows.length > 0) return null

      // Empty state — custom component overrides everything
      if (appearance?.emptyStateComponent) {
        return h(
          'div',
          { style: overlayStyle, class: 'yg-overlay yg-overlay--empty' },
          [h(appearance.emptyStateComponent)]
        )
      }

      // Filtered empty (raw had data but filters removed everything)
      if (isFilteredEmpty) {
        const title =
          appearance?.filteredEmptyState?.title ?? 'No matching results'
        const description =
          appearance?.filteredEmptyState?.description ??
          'Try adjusting your filters'
        const icon = appearance?.filteredEmptyState?.icon
        return h(
          'div',
          {
            class: 'yg-overlay yg-overlay--empty',
            style: overlayStyle,
            role: 'status',
            'aria-label': title,
            'aria-live': 'polite',
          },
          [icon ?? iconBubble('🔍'), messageBlock(title, description)]
        )
      }

      // Generic empty (no data ever loaded)
      const title = appearance?.emptyState?.title ?? 'No data'
      const description =
        appearance?.emptyState?.description ?? 'No rows to display'
      const icon = appearance?.emptyState?.icon
      return h(
        'div',
        {
          class: 'yg-overlay yg-overlay--empty',
          style: overlayStyle,
          role: 'status',
          'aria-label': title,
          'aria-live': 'polite',
        },
        [icon ?? iconBubble('📭'), messageBlock(title, description)]
      )
    }
  },
})
