// ============================================
// @elitegrid/vue — useGrid
// DOM <-> engine bridge.
//
// IDEOLOGY:
// The engine doesn't touch the DOM. The framework owns the DOM.
// But the viewport plugin needs three pieces of DOM information:
//   1. Container size  → so virtualisation can compute visible rows
//   2. Scroll position → so the visible window can shift
//
// This composable is the wire that carries those signals from the
// DOM into the engine via its event bus.
// ============================================

import { ref, onMounted, onBeforeUnmount, type Ref } from 'vue'
import { GridEvent } from '@elitegrid/core'
import type { GridInstance } from '../create-grid'

export interface UseGridReturn {
  // Template ref — bind to the scroll container element via `ref="containerRef"`
  containerRef: Ref<HTMLDivElement | null>
}

const CHECKBOX_WIDTH = 48

export function useGrid(grid: GridInstance): UseGridReturn {
  const containerRef = ref<HTMLDivElement | null>(null)

  // ResizeObserver is created once, reused across the component lifecycle.
  // Cleaned up in onBeforeUnmount to avoid leaks.
  let observer: ResizeObserver | null = null

  // rAF coalescer for scroll — scroll events fire faster than paint can keep up.
  // We coalesce multiple scroll events per frame into one engine emit.
  let rafId: number | null = null
  let initialRafId: number | null = null

  const handleScroll = () => {
    if (rafId !== null) return
    rafId = requestAnimationFrame(() => {
      rafId = null
      const el = containerRef.value
      if (!el) return
      grid.kernel.eventBus.emit(GridEvent.SCROLL_CHANGED, {
        scrollTop: el.scrollTop,
        scrollLeft: el.scrollLeft,
      })
    })
  }

  onMounted(() => {
    const container = containerRef.value
    if (!container) return

    // When selection checkboxes are shown, the 48px checkbox column is
    // rendered outside the engine's column model. We subtract it from the
    // reported container width so column widths don't overflow horizontally.
    const showCheckboxes =
      grid.options.selection?.mode !== 'none' &&
      (grid.options.selection?.showCheckboxes ?? true)

    // ── Emit initial size ──────────────────────────────────────────────
    // clientWidth always excludes the scrollbar — overflowY:scroll on the
    // body keeps the scrollbar track always present, so clientWidth stays
    // stable across content changes.
    const emitSize = () => {
      const width =
        container.clientWidth - (showCheckboxes ? CHECKBOX_WIDTH : 0)
      const height = container.clientHeight
      if (width > 0 && height > 0) {
        grid.kernel.eventBus.emit(GridEvent.CONTAINER_RESIZED, {
          width,
          height,
        })
      }
    }

    // Defer initial size to rAF — useMounted runs after paint but the
    // scrollbar from overflowY:scroll may not be laid out yet on first read.
    initialRafId = requestAnimationFrame(() => {
      initialRafId = null
      emitSize()
    })

    // ── ResizeObserver — watches for later size changes ────────────────
    observer = new ResizeObserver(() => {
      // Re-read clientWidth/clientHeight from the DOM rather than trusting
      // entry.contentRect — clientWidth correctly excludes the scrollbar
      // track, contentRect does not when the scrollbar is reserved.
      emitSize()
    })
    observer.observe(container)

    // Passive scroll listener — we don't call preventDefault so passive
    // is safe and tells the browser it can scroll without waiting for us.
    container.addEventListener('scroll', handleScroll, { passive: true })
  })

  onBeforeUnmount(() => {
    observer?.disconnect()
    observer = null
    if (rafId !== null) {
      cancelAnimationFrame(rafId)
      rafId = null
    }
    if (initialRafId !== null) {
      cancelAnimationFrame(initialRafId)
      initialRafId = null
    }
    containerRef.value?.removeEventListener('scroll', handleScroll)
  })

  return { containerRef }
}

