// ============================================
// @elitegrid/vue — date utilities
// Local-timezone-safe parsing and formatting for <input type="date">.
//
// `new Date('YYYY-MM-DD')` parses as UTC midnight, which displays as the
// previous day in timezones behind UTC. These helpers always use local time.
//
// Mirror of react/src/utils/date.ts
// ============================================

export function parseLocalDate(s: string): Date | null {
  if (!s) return null
  const parts = s.split('-').map(Number)
  if (parts.length !== 3 || parts.some((n) => isNaN(n))) return null
  const [year, month, day] = parts as [number, number, number]
  return new Date(year, month - 1, day)
}

export function formatDateInput(value: unknown): string {
  if (!value) return ''
  const date = value instanceof Date ? value : new Date(value as string)
  if (isNaN(date.getTime())) return ''
  const y = date.getFullYear()
  const m = String(date.getMonth() + 1).padStart(2, '0')
  const d = String(date.getDate()).padStart(2, '0')
  return `${y}-${m}-${d}`
}
