// ============================================
// @elitegrid/vue — useFocusManager
// Moves real DOM focus when the focus plugin
// changes the focused cell.
//
// IDEOLOGY:
// The engine emits FOCUS_CHANGED with a logical CellPosition.
// We need to translate that logical position into a physical
// .focus() call on the matching DOM element.
//
// Cells are virtualised — only the visible window exists in the
// DOM. So we use data-rowid + data-columnid attributes on each
// rendered cell, and querySelector to find the right element.
//
// One rAF delay before focusing — if the focused cell is outside
// the current scroll window, the engine emits SCROLL_TO_ROW first
// and only the next paint contains the newly visible rows. rAF
// gives Vue one frame to render those rows before we try to focus.
// ============================================

import { onMounted, onBeforeUnmount, type Ref } from 'vue'
import { GridEvent } from '@elitegrid/core'
import type { GridInstance } from '../create-grid'

export function useFocusManager(
  grid: GridInstance,
  containerRef: Ref<HTMLDivElement | null>
): void {
  let unsubscribe: (() => void) | null = null

  onMounted(() => {
    unsubscribe = grid.kernel.eventBus.on(
      GridEvent.FOCUS_CHANGED,
      (payload: unknown) => {
        const { cell } = payload as {
          cell: { rowId: string; columnId: string } | null
        }
        if (!cell) return

        // rAF delay — see file-level comment for why this matters.
        requestAnimationFrame(() => {
          const container = containerRef.value
          if (!container) return

          const el = container.querySelector<HTMLElement>(
            `[data-rowid="${cell.rowId}"][data-columnid="${cell.columnId}"]`
          )
          if (el) {
            // preventScroll: false → browser scrolls element into view
            // if it's outside the visible area. That's the cheap path —
            // viewport plugin doesn't have to scroll explicitly.
            el.focus({ preventScroll: false })
          }
        })
      }
    )
  })

  onBeforeUnmount(() => {
    unsubscribe?.()
    unsubscribe = null
  })
}
