// ============================================
// @elitegrid/vue — GridFilterPopover
// Per-column filter UI shown when the user clicks
// the filter icon in the header.
//
// IDEOLOGY:
// Each column's filter type (text / number / date / boolean)
// determines which operators are available and how many inputs
// are needed. The popover translates user input into the
// engine's ColumnFilter shape and writes it via FilterPlugin.
//
// State here is purely local (operator, value, valueTo) — the
// engine never sees a partially-typed value. Only on "Apply"
// do we commit the full filter to the engine.
//
// Mirror of react/src/components/Gridfilterpopover.tsx
// ============================================

import {
  defineComponent,
  h,
  ref,
  computed,
  onMounted,
  onBeforeUnmount,
  type PropType,
  type Ref,
} from 'vue'
import type {
  TextFilterOperator,
  NumberFilterOperator,
  DateFilterOperator,
  BooleanFilterOperator,
  ColumnFilter,
} from '@elitegrid/core'
import { useGridContext } from '../context/GridContext'
import { parseLocalDate } from '../utils/date'

type FilterType = 'text' | 'number' | 'date' | 'boolean'

const TEXT_OPERATORS: { value: TextFilterOperator; label: string }[] = [
  { value: 'contains', label: 'Contains' },
  { value: 'notContains', label: 'Does not contain' },
  { value: 'equals', label: 'Equals' },
  { value: 'notEquals', label: 'Does not equal' },
  { value: 'startsWith', label: 'Starts with' },
  { value: 'endsWith', label: 'Ends with' },
  { value: 'isEmpty', label: 'Is empty' },
  { value: 'isNotEmpty', label: 'Is not empty' },
]

const NUMBER_OPERATORS: { value: NumberFilterOperator; label: string }[] = [
  { value: 'equals', label: 'Equals' },
  { value: 'notEquals', label: 'Does not equal' },
  { value: 'greaterThan', label: 'Greater than' },
  { value: 'greaterThanOrEqual', label: 'Greater than or equal' },
  { value: 'lessThan', label: 'Less than' },
  { value: 'lessThanOrEqual', label: 'Less than or equal' },
  { value: 'between', label: 'Between' },
  { value: 'isEmpty', label: 'Is empty' },
  { value: 'isNotEmpty', label: 'Is not empty' },
]

const DATE_OPERATORS: { value: DateFilterOperator; label: string }[] = [
  { value: 'equals', label: 'Equals' },
  { value: 'notEquals', label: 'Does not equal' },
  { value: 'before', label: 'Before' },
  { value: 'after', label: 'After' },
  { value: 'between', label: 'Between' },
  { value: 'isEmpty', label: 'Is empty' },
  { value: 'isNotEmpty', label: 'Is not empty' },
]

const BOOLEAN_OPERATORS: { value: BooleanFilterOperator; label: string }[] = [
  { value: 'equals', label: 'Equals' },
  { value: 'isEmpty', label: 'Is empty' },
  { value: 'isNotEmpty', label: 'Is not empty' },
]

const NO_INPUT_OPERATORS = ['isEmpty', 'isNotEmpty']
const TWO_INPUT_OPERATORS = ['between']

export const GridFilterPopover = defineComponent({
  name: 'GridFilterPopover',
  props: {
    columnId: { type: String, required: true },
    filterType: { type: String as PropType<FilterType>, required: true },
    anchorRef: {
      type: Object as PropType<Ref<HTMLElement | null>>,
      required: true,
    },
    onClose: { type: Function as PropType<() => void>, required: true },
    placement: {
      type: String as PropType<'bottom' | 'top' | 'auto'>,
      default: 'auto',
    },
  },
  setup(props) {
    const grid = useGridContext()
    const popoverRef = ref<HTMLDivElement | null>(null)

    // Read current filter state for this column to pre-populate inputs.
    const currentFilter = grid.kernel.store.read('filtered').filterModel
      .columns[props.columnId] as (ColumnFilter & { valueTo?: unknown }) | undefined

    const defaultOperator = (() => {
      switch (props.filterType) {
        case 'text':
          return 'contains'
        case 'number':
          return 'equals'
        case 'date':
          return 'equals'
        case 'boolean':
          return 'equals'
      }
    })()

    const operator = ref<string>(currentFilter?.operator ?? defaultOperator)
    const value = ref<string>(
      currentFilter?.value != null ? String(currentFilter.value) : ''
    )
    const valueTo = ref<string>(
      currentFilter?.valueTo != null ? String(currentFilter.valueTo) : ''
    )
    const boolValue = ref<string>(
      currentFilter?.value != null ? String(currentFilter.value) : 'true'
    )
    const betweenError = ref<string | null>(null)

    // ── Position popover relative to anchor icon ──────────────────
    // position:fixed â†’ top/left are VIEWPORT-relative, so do NOT add
    // scrollX/scrollY. Recalculate on scroll and resize so the popover
    // stays attached to the anchor as the page moves.
    const position = ref({ top: 0, left: 0 })

    const calculate = () => {
      const anchorEl = props.anchorRef.value
      if (!anchorEl) return
      const rect = anchorEl.getBoundingClientRect()
      const POPOVER_HEIGHT = 280
      const POPOVER_WIDTH = 260
      const spaceBelow = window.innerHeight - rect.bottom
      const spaceAbove = rect.top
      const left = Math.min(rect.left, window.innerWidth - POPOVER_WIDTH - 8)
      const openAbove =
        props.placement === 'top' ||
        (props.placement === 'auto' &&
          spaceBelow < POPOVER_HEIGHT &&
          spaceAbove > spaceBelow)
      position.value = {
        top: openAbove ? rect.top - POPOVER_HEIGHT - 4 : rect.bottom + 4,
        left,
      }
    }

    // ── Close on outside click / Escape ──────────
    const handleClickOutside = (e: MouseEvent) => {
      if (
        popoverRef.value &&
        !popoverRef.value.contains(e.target as Node) &&
        !props.anchorRef.value?.contains(e.target as Node)
      ) {
        props.onClose()
      }
    }
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.key === 'Escape') props.onClose()
    }
    onMounted(() => {
      calculate()
      window.addEventListener('resize', calculate)
      window.addEventListener('scroll', calculate, true)
      document.addEventListener('mousedown', handleClickOutside)
      document.addEventListener('keydown', handleKeyDown)
    })
    onBeforeUnmount(() => {
      window.removeEventListener('resize', calculate)
      window.removeEventListener('scroll', calculate, true)
      document.removeEventListener('mousedown', handleClickOutside)
      document.removeEventListener('keydown', handleKeyDown)
    })

    // ── Operators for current filter type ─────
    const operators = computed(() => {
      switch (props.filterType) {
        case 'text':
          return TEXT_OPERATORS
        case 'number':
          return NUMBER_OPERATORS
        case 'date':
          return DATE_OPERATORS
        case 'boolean':
          return BOOLEAN_OPERATORS
      }
    })

    const needsNoInput = computed(() =>
      NO_INPUT_OPERATORS.includes(operator.value)
    )
    const needsTwoInputs = computed(() =>
      TWO_INPUT_OPERATORS.includes(operator.value)
    )

    // ── Apply / Clear ─────────────────────────
    const handleApply = () => {
      betweenError.value = null

      // Validate between range — from must be <= to
      if (needsTwoInputs.value && props.filterType === 'number') {
        const from = Number(value.value)
        const to = Number(valueTo.value)
        if (!isNaN(from) && !isNaN(to) && from > to) {
          betweenError.value = '"From" must be less than or equal to "To"'
          return
        }
      }
      if (
        needsTwoInputs.value &&
        props.filterType === 'date' &&
        value.value &&
        valueTo.value
      ) {
        const from = parseLocalDate(value.value)
        const to = parseLocalDate(valueTo.value)
        if (from && to && from > to) {
          betweenError.value =
            '"From" date must be before or equal to "To" date'
          return
        }
      }

      const currentModel = grid.kernel.store.read('filtered').filterModel

      if (needsNoInput.value) {
        grid.plugins.filter.setFilterModel({
          columns: {
            ...currentModel.columns,
            [props.columnId]: {
              type: props.filterType,
              operator: operator.value,
            } as ColumnFilter,
          },
        })
      } else if (props.filterType === 'boolean') {
        grid.plugins.filter.setFilterModel({
          columns: {
            ...currentModel.columns,
            [props.columnId]: {
              type: 'boolean',
              operator: operator.value,
              value: boolValue.value === 'true',
            } as ColumnFilter,
          },
        })
      } else if (props.filterType === 'number') {
        grid.plugins.filter.setFilterModel({
          columns: {
            ...currentModel.columns,
            [props.columnId]: {
              type: 'number',
              operator: operator.value,
              value: Number(value.value),
              ...(needsTwoInputs.value
                ? { valueTo: Number(valueTo.value) }
                : {}),
            } as ColumnFilter,
          },
        })
      } else if (props.filterType === 'date') {
        // Use parseLocalDate so the filter value matches local midnight,
        // not UTC midnight (which would be wrong for negative-UTC zones).
        grid.plugins.filter.setFilterModel({
          columns: {
            ...currentModel.columns,
            [props.columnId]: {
              type: 'date',
              operator: operator.value,
              value: parseLocalDate(value.value),
              ...(needsTwoInputs.value
                ? { valueTo: parseLocalDate(valueTo.value) }
                : {}),
            } as ColumnFilter,
          },
        })
      } else {
        grid.plugins.filter.setFilterModel({
          columns: {
            ...currentModel.columns,
            [props.columnId]: {
              type: 'text',
              operator: operator.value,
              value: value.value,
            } as ColumnFilter,
          },
        })
      }
      props.onClose()
    }

    const handleClear = () => {
      const currentModel = grid.kernel.store.read('filtered').filterModel
      const newColumns = { ...currentModel.columns }
      delete newColumns[props.columnId]
      grid.plugins.filter.setFilterModel({ columns: newColumns })
      props.onClose()
    }

    const handleKeyPress = (e: KeyboardEvent) => {
      if (e.key === 'Enter') handleApply()
    }

    // ── Shared styles ─────────────────────────
    const inputStyle = {
      width: '100%',
      height: '32px',
      padding: '0 8px',
      border: '1px solid var(--eg-border)',
      borderRadius: '6px',
      fontSize: '0.875rem',
      color: 'var(--eg-text)',
      backgroundColor: 'var(--eg-surface)',
      boxSizing: 'border-box' as const,
      outline: 'none',
      fontFamily: 'inherit',
    }
    const labelStyle = {
      fontSize: '0.75rem',
      fontWeight: 600,
      color: 'var(--eg-muted-text)',
      marginBottom: '4px',
      display: 'block',
      textTransform: 'uppercase' as const,
      letterSpacing: '0.05em',
    }

    return () => {
      const inputType =
        props.filterType === 'number'
          ? 'number'
          : props.filterType === 'date'
            ? 'date'
            : 'text'

      // ── Header row ──────────────────────────
      const header = h(
        'div',
        {
          style: {
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'space-between',
            paddingBottom: '8px',
            borderBottom: '1px solid var(--eg-border)',
          },
        },
        [
          h(
            'span',
            {
              style: {
                fontSize: '0.875rem',
                fontWeight: 600,
                color: 'var(--eg-text)',
              },
            },
            'Filter'
          ),
          h(
            'button',
            {
              onClick: () => props.onClose(),
              style: {
                background: 'none',
                border: 'none',
                cursor: 'pointer',
                fontSize: '1rem',
                color: 'var(--eg-muted-text)',
                padding: 0,
                lineHeight: 1,
              },
            },
            '✕'
          ),
        ]
      )

      // ── Operator selector ───────────────────
      const operatorSelector = h('div', null, [
        h('label', { style: labelStyle }, 'Condition'),
        h(
          'select',
          {
            value: operator.value,
            onChange: (e: Event) => {
              operator.value = (e.target as HTMLSelectElement).value
            },
            style: { ...inputStyle, height: '34px' },
          },
          operators.value.map((op) =>
            h('option', { key: op.value, value: op.value }, op.label)
          )
        ),
      ])

      // ── Value inputs (varies by filter type) ──
      let valueInputs: ReturnType<typeof h> | null = null
      if (!needsNoInput.value) {
        if (props.filterType === 'boolean') {
          valueInputs = h('div', null, [
            h('label', { style: labelStyle }, 'Value'),
            h(
              'select',
              {
                value: boolValue.value,
                onChange: (e: Event) => {
                  boolValue.value = (e.target as HTMLSelectElement).value
                },
                style: { ...inputStyle, height: '34px' },
              },
              [
                h('option', { value: 'true' }, 'True'),
                h('option', { value: 'false' }, 'False'),
              ]
            ),
          ])
        } else {
          valueInputs = h(
            'div',
            {
              style: { display: 'flex', flexDirection: 'column', gap: '6px' },
            },
            [
              h('div', null, [
                h(
                  'label',
                  { style: labelStyle },
                  needsTwoInputs.value ? 'From' : 'Value'
                ),
                h('input', {
                  type: inputType,
                  value: value.value,
                  onInput: (e: Event) => {
                    value.value = (e.target as HTMLInputElement).value
                  },
                  onKeydown: handleKeyPress,
                  placeholder: needsTwoInputs.value
                    ? 'From...'
                    : 'Filter value...',
                  style: inputStyle,
                  autofocus: true,
                }),
              ]),
              needsTwoInputs.value
                ? h('div', null, [
                    h('label', { style: labelStyle }, 'To'),
                    h('input', {
                      type: inputType,
                      value: valueTo.value,
                      onInput: (e: Event) => {
                        valueTo.value = (e.target as HTMLInputElement).value
                      },
                      onKeydown: handleKeyPress,
                      placeholder: 'To...',
                      style: inputStyle,
                    }),
                  ])
                : null,
            ]
          )
        }
      }

      // ── Action buttons ──────────────────────
      const actions = h(
        'div',
        { style: { display: 'flex', gap: '6px', paddingTop: '4px' } },
        [
          h(
            'button',
            {
              onClick: handleClear,
              style: {
                flex: 1,
                height: '32px',
                border: '1px solid var(--eg-border)',
                borderRadius: '6px',
                backgroundColor: 'var(--eg-surface)',
                color: 'var(--eg-muted-text)',
                fontSize: '0.875rem',
                cursor: 'pointer',
                fontFamily: 'inherit',
              },
            },
            'Clear'
          ),
          h(
            'button',
            {
              onClick: handleApply,
              style: {
                flex: 1,
                height: '32px',
                border: 'none',
                borderRadius: '6px',
                backgroundColor: 'var(--eg-primary)',
                color: 'var(--eg-primary-text)',
                fontSize: '0.875rem',
                fontWeight: 600,
                cursor: 'pointer',
                fontFamily: 'inherit',
              },
            },
            'Apply'
          ),
        ]
      )

      const errorBlock = betweenError.value
        ? h(
            'div',
            {
              role: 'alert',
              style: {
                marginTop: '6px',
                fontSize: '0.75rem',
                color: 'var(--eg-error)',
                padding: '4px 0',
              },
            },
            betweenError.value
          )
        : null

      return h(
        'div',
        {
          ref: popoverRef,
          style: {
            position: 'fixed',
            top: `${position.value.top}px`,
            left: `${position.value.left}px`,
            width: '260px',
            backgroundColor: 'var(--eg-surface)',
            border: '1px solid var(--eg-border)',
            borderRadius: '8px',
            boxShadow: '0 4px 16px rgba(0,0,0,0.12)',
            zIndex: 1000,
            padding: '12px',
            display: 'flex',
            flexDirection: 'column',
            gap: '10px',
          },
        },
        [header, operatorSelector, valueInputs, actions, errorBlock]
      )
    }
  },
})
