// ============================================
// @elitegrid/vue — utils/columnWidths
// Computes pixel widths for every visible column.
//
// IDEOLOGY:
// Pure function, no Vue dependency. Identical implementation
// to the React adapter — width math doesn't depend on framework.
//
// Algorithm:
//   1. Walk visible columns; split into "fixed" and "flex" buckets.
//   2. Fixed columns claim their requested width directly.
//   3. Remaining container width is distributed proportionally
//      across flex columns based on their flex weights.
//   4. If fixed columns already overflow the container, flex
//      columns fall back to minWidth — the user gets horizontal
//      scroll instead of negative widths.
// ============================================

import type { ColumnDefinition } from '@elitegrid/core'
import type { ColumnDef } from '../create-grid'

export function calculateColumnWidths(
  definitions: ColumnDefinition[],
  columnOptions: ColumnDef[],
  containerWidth: number
): Map<string, number> {
  const widths = new Map<string, number>()

  if (definitions.length === 0 || containerWidth === 0) return widths

  const fixedColumns: Array<{ id: string; width: number }> = []
  const flexColumns: Array<{ id: string; flex: number; minWidth: number }> = []

  definitions.forEach((col) => {
    if (!col.visible) return

    const colOption = columnOptions.find(
      (c) => (c.field as string) === col.field
    )
    const flex = colOption?.size?.flex
    const minWidth = col.minWidth ?? colOption?.size?.minWidth ?? 50

    // col.width is set in the store when a column has been explicitly
    // resized — treat as fixed regardless of whether `flex` was set.
    if (col.width != null) {
      fixedColumns.push({ id: col.id, width: col.width })
    } else if (flex != null && flex > 0) {
      flexColumns.push({ id: col.id, flex, minWidth })
    } else {
      fixedColumns.push({ id: col.id, width: colOption?.size?.width ?? 150 })
    }
  })

  fixedColumns.forEach(({ id, width }) => widths.set(id, width))

  const fixedTotal = fixedColumns.reduce((sum, c) => sum + c.width, 0)
  const remainingWidth = containerWidth - fixedTotal

  if (flexColumns.length > 0) {
    if (remainingWidth > 0) {
      const totalFlex = flexColumns.reduce((sum, c) => sum + c.flex, 0)
      flexColumns.forEach(({ id, flex, minWidth }) => {
        const calculated = (flex / totalFlex) * remainingWidth
        widths.set(id, Math.max(minWidth, Math.floor(calculated)))
      })
    } else {
      // Fixed columns already fill the container — flex falls back to
      // minWidth, reachable via horizontal scroll.
      flexColumns.forEach(({ id, minWidth }) => widths.set(id, minWidth))
    }
  }

  return widths
}
