// ============================================
// @elitegrid/core — Dev-mode helper
//
// Avoids referencing `process` (Node) or any
// DOM globals. Bundlers (Vite, webpack, esbuild)
// replace the `__DEV__` string literal at build
// time, so production bundles dead-code-eliminate
// all dev-only branches automatically.
//
// Usage:
//   import { isDev, devWarn, devError } from '../../utils/dev'
//   devWarn('[EliteGrid] Something looks wrong')
//   devError('[EliteGrid] Fatal config error')   // throws in dev
// ============================================

/**
 * Returns true when running outside a minified production build.
 *
 * `__DEV__` is injected by the bundler (Vite define, webpack DefinePlugin,
 * esbuild define). Falls back to `true` in unknown environments so that
 * dev warnings are never silently swallowed during local development or
 * testing.
 *
 * No `process`, no `window`, no Node or Vite types required.
 */
export function isDev(): boolean {
  // Bundlers replace this literal at build time
  if (typeof __DEV__ !== 'undefined') {
    return __DEV__ as boolean
  }
  // Unknown environment (unit tests, CDN usage, etc.) — assume dev
  return true
}

// ── Safe console access ───────────────────────
// `console` is not in the ES2020 lib (it's a host object).
// Accessing it via `Function('return this')()` or globalThis avoids
// the TypeScript error without requiring 'dom' or '@types/node'.

// eslint-disable-next-line @typescript-eslint/no-explicit-any
const _console =
  typeof globalThis !== 'undefined' && (globalThis as any).console
    ? (globalThis as any).console
    : { warn: () => {}, error: () => {} }

/**
 * Emits a console.warn in dev mode only. No-op in production.
 */
export function devWarn(message: string): void {
  if (isDev()) {
    _console.warn(message)
  }
}

/**
 * Throws an Error in dev mode; emits console.error + returns in production.
 */
export function devError(message: string): void {
  if (isDev()) {
    throw new Error(message)
  }
  _console.error(message)
}

// Ambient declaration so TypeScript accepts __DEV__ without @types/node.
// Your bundler's define config is what actually provides the runtime value.
declare const __DEV__: boolean | undefined
