// ============================================
// @elitegrid/vue — GridCell
// Renders a single cell value (or its inline editor).
//
// IDEOLOGY:
// The cell is the smallest reactive unit. It subscribes to
// `editing` and `focus` namespaces to know whether to render
// the editor or the display value, and whether to draw the
// focus ring.
//
// Selection / focus / edit click logic is identical to React —
// cells own their own clicks (stopPropagation) so the engine
// can distinguish "click on cell" vs "click on row padding".
//
// Mirror of react/src/components/GridCell.tsx
// ============================================

import { defineComponent, h, computed, type PropType } from 'vue'
import { GridEvent } from '@elitegrid/core'
import type { CellPosition, ColumnId, ColumnEditorConfig } from '@elitegrid/core'
import type { ColumnDef } from '../create-grid'
import { useGridContext } from '../context/GridContext'
import { useEditState, useFocusState } from '../composables/useGridStates'
import { GridCellEditor } from './GridCellEditor'

export const GridCell = defineComponent({
  name: 'GridCell',
  props: {
    rowId: { type: String, required: true },
    columnId: { type: String as PropType<ColumnId>, required: true },
    columnIndex: { type: Number, required: true },
    rowIndex: { type: Number, required: true },
    // getCellValue returns the FULL row (the cell-value plugin needs full
    // row context for formatters that depend on sibling fields).
    getCellValue: {
      type: Function as PropType<() => unknown>,
      required: true,
    },
    columnWidths: {
      type: Object as PropType<Map<string, number>>,
      required: true,
    },
    columnDefMap: {
      type: Object as PropType<Map<string, unknown>>,
      required: true,
    },
    columnOptionsMap: {
      type: Object as PropType<Map<string, ColumnDef>>,
      required: true,
    },
  },
  setup(props) {
    const grid = useGridContext()
    const editState = useEditState(grid)
    const focusState = useFocusState(grid)

    const isFocused = computed(
      () =>
        focusState.value.focusedCell?.rowId === props.rowId &&
        focusState.value.focusedCell?.columnId === props.columnId
    )
    const isEditing = computed(
      () =>
        editState.value.isEditing &&
        editState.value.editingCell?.rowId === props.rowId &&
        editState.value.editingCell?.columnId === props.columnId
    )

    return () => {
      const { options } = grid

      const selectionMode = options.selection?.mode ?? 'none'
      const selectOnRowClick = options.selection?.selectOnRowClick ?? true
      const checkboxOnly = options.selection?.checkboxOnly ?? false

      const colDef = props.columnDefMap.get(props.columnId) as
        | { id: string; width?: number; editable?: boolean }
        | undefined
      if (!colDef) return null

      // Full row object — needed by CellValuePlugin for cross-field context.
      // The pipeline never wraps rows in NormalizedRow; rows are plain TData.
      // Checking ._data would break developers whose data has a `_data` field.
      const rawRowObj = props.getCellValue() as Record<string, unknown> | null
      const value = rawRowObj?.[props.columnId]
      const rawRow = rawRowObj as Record<string, unknown>

      // ── Per-row editable resolution ─────────────────────────────────
      // When edit.enabled is a function, normalizeColumns marks the engine
      // column as editable:true so EDIT_START_REQUESTED is allowed through.
      // The actual per-row gate runs HERE at render time.
      const colOptions = props.columnOptionsMap.get(props.columnId)
      const enabledConfig = colOptions?.edit?.enabled
      const isEditable =
        typeof enabledConfig === 'function'
          ? enabledConfig(rawRowObj as unknown)
          : (colDef.editable ?? false)

      const colWidth =
        props.columnWidths.get(props.columnId) ?? colDef.width ?? 150

      // CellValuePlugin owns formatting — it falls back to rawToString
      // when no formatter is configured for the column.
      const cellValuePlugin = grid.plugins.cellValue
      const displayValue = cellValuePlugin
        ? cellValuePlugin.getDisplayValue(rawRow, props.columnId)
        : value === null || value === undefined
          ? ''
          : String(value)

      // cellClass — string or function form
      const cellClassOption = colOptions?.display?.cellClass
      const extraClass =
        typeof cellClassOption === 'function'
          ? cellClassOption(value, rawRow as unknown)
          : (cellClassOption ?? '')

      const onCellFocus = () => {
        if (!isFocused.value) {
          grid.kernel.eventBus.emit(GridEvent.FOCUS_SET_REQUESTED, {
            cell: {
              rowId: props.rowId,
              columnId: props.columnId,
              rowIndex: props.rowIndex,
              columnIndex: props.columnIndex,
            } satisfies CellPosition,
          })
        }
      }

      const onCellDblClick = (e: MouseEvent) => {
        e.stopPropagation()
        if (!isEditable) return
        // Only handle double-click if trigger is 'doubleClick' (default).
        const trigger = options.editing?.trigger ?? 'doubleClick'
        if (trigger !== 'doubleClick') return
        const cell: CellPosition = {
          rowId: props.rowId,
          columnId: props.columnId,
          rowIndex: props.rowIndex,
          columnIndex: props.columnIndex,
        }
        grid.kernel.eventBus.emit(GridEvent.EDIT_START_REQUESTED, { cell })
      }

      const onCellClick = (e: MouseEvent) => {
        // Cell owns its own clicks — stop here so row's click handler
        // doesn't double-fire selection.
        e.stopPropagation()
        if (e.detail > 1) return // second click of a double-click
        if (isEditing.value) return

        // ── Click-to-edit ────────────────────────────────────────────
        // When trigger is 'click', a plain click on an editable cell
        // opens the editor (Shift/Ctrl/Meta still select for ranges).
        const trigger = options.editing?.trigger ?? 'doubleClick'
        if (
          trigger === 'click' &&
          isEditable &&
          !e.shiftKey &&
          !e.ctrlKey &&
          !e.metaKey
        ) {
          const cell: CellPosition = {
            rowId: props.rowId,
            columnId: props.columnId,
            rowIndex: props.rowIndex,
            columnIndex: props.columnIndex,
          }
          grid.kernel.eventBus.emit(GridEvent.EDIT_START_REQUESTED, { cell })
          return
        }

        if (selectionMode === 'none' || !selectOnRowClick || checkboxOnly)
          return

        const editingEnabled = options.editing?.enabled ?? false
        const hasModifier = e.shiftKey || e.ctrlKey || e.metaKey

        // If editing is enabled, plain-click on an already-selected row
        // should NOT clear selection — user may be about to double-click
        // to edit. Modifier-clicks always work.
        if (editingEnabled && !hasModifier) {
          const { selectedIds } = grid.kernel.store.read('selection')
          if (selectedIds.has(props.rowId)) return
        }

        grid.kernel.eventBus.emit(GridEvent.ROW_CLICK_SELECTION, {
          rowId: props.rowId,
          shiftKey: e.shiftKey,
          ctrlKey: e.ctrlKey,
          metaKey: e.metaKey,
        })
      }

      const style = {
        width: `${colWidth}px`,
        minWidth: `${colWidth}px`,
        maxWidth: `${colWidth}px`,
        height: '100%',
        display: 'flex',
        alignItems: 'center',
        padding: 'var(--eg-cell-padding, 0 12px)',
        boxSizing: 'border-box' as const,
        overflow: 'hidden',
        whiteSpace: 'nowrap' as const,
        textOverflow: 'ellipsis',
        fontSize: 'var(--eg-cell-font-size, 0.875rem)',
        color: 'var(--eg-cell-text)',
        borderRight: options.appearance?.showColumnBorders
          ? 'var(--eg-cell-border)'
          : undefined,
        flexShrink: 0,
        // Inset focus ring so the outline doesn't get clipped by
        // overflow:hidden on the cell or row container.
        outline:
          isFocused.value && !isEditing.value
            ? '2px solid var(--eg-primary)'
            : 'none',
        outlineOffset: '-2px',
        position: 'relative' as const,
      }

      const content = isEditing.value
        ? h(GridCellEditor, {
            cell: editState.value.editingCell!,
            currentValue: editState.value.currentValue,
            isValid: editState.value.isValid,
            validationError: editState.value.validationError,
            editorConfig:
              (grid.plugins.edit as unknown as { getColumnEditor: (id: string) => ColumnEditorConfig | undefined })?.getColumnEditor(props.columnId) ??
              null,
            colWidth,
            rowHeight: 40,
          })
        : h(
            'span',
            {
              style: {
                overflow: 'hidden',
                textOverflow: 'ellipsis',
                whiteSpace: 'nowrap',
                width: '100%',
              },
              title: displayValue,
            },
            displayValue
          )

      return h(
        'div',
        {
          class: ['yg-cell', extraClass].filter(Boolean).join(' '),
          role: 'gridcell',
          'aria-colindex': props.columnIndex + 1,
          'aria-readonly': !isEditable,
          'data-rowid': props.rowId,
          'data-columnid': props.columnId,
          tabindex: isFocused.value ? 0 : -1,
          onFocus: onCellFocus,
          onDblclick: onCellDblClick,
          onClick: onCellClick,
          style,
        },
        [content]
      )
    }
  },
})
