// ============================================
// @elitegrid/core — Focus Plugin
// Keyboard navigation and focused cell state
//
// Owns:
//   - 'focus' store namespace
//   - All keyboard navigation math
//   - FOCUS_CHANGED event
//
// Listens to:
//   - FOCUS_SET_REQUESTED  — jump to a specific cell
//   - FOCUS_MOVE_REQUESTED — move relative to current cell
//   - DATA_SET / DATA_CHANGED / PAGE_CHANGED — clear focus
//     when the dataset changes underneath
//
// Does NOT:
//   - Touch the DOM (that's the adapter's job)
//   - Know about editing (EditPlugin listens to FOCUS_CHANGED)
//   - Know about screen readers (AnnouncementPlugin does that)
//
// Navigation directions:
//   'up'       — previous row, same column
//   'down'     — next row, same column
//   'left'     — previous visible column, same row
//   'right'    — next visible column, same row
//   'next'     — Tab: next cell (wraps rows), editableOnly when in edit mode
//   'prev'     — Shift+Tab: previous cell (wraps rows)
//   'rowStart' — Home: first visible column in current row
//   'rowEnd'   — End: last visible column in current row
//   'first'    — Ctrl+Home: first cell in grid
//   'last'     — Ctrl+End: last cell in grid
// ============================================

import type { Plugin, PluginContext } from '../../kernel/index'
import { GridEvent } from '../../event-bus/events'
import type { CellPosition, ColumnId } from '../../types/index'
import { ROW_MODEL_PLUGIN_ID } from '../row-model/index'
import type { RowModelPlugin } from '../row-model/index'

// ── Plugin ID ─────────────────────────────────

export const FOCUS_PLUGIN_ID = 'focus'

// ── Move direction ─────────────────────────────

export type FocusDirection =
  | 'up'
  | 'down'
  | 'left'
  | 'right'
  | 'next'
  | 'prev'
  | 'rowStart'
  | 'rowEnd'
  | 'first'
  | 'last'

// ── Event payloads ─────────────────────────────

export interface FocusSetPayload {
  cell: CellPosition
}

export interface FocusMovePayload {
  direction: FocusDirection
  // When true — Tab/Shift+Tab skip non-editable columns
  editableOnly?: boolean
}

export interface FocusChangedPayload {
  cell: CellPosition | null
  previousCell: CellPosition | null
}

// ── Implementation ─────────────────────────────

export class FocusPlugin implements Plugin {
  readonly id = FOCUS_PLUGIN_ID

  private context!: PluginContext

  // Cleanup functions — all subscriptions stored here for leak-free destroy
  private cleanups: Array<() => void> = []

  // ── Init ──────────────────────────────────

  init(context: PluginContext): void {
    this.context = context

    // Initialise focus namespace
    context.store.write('focus', {
      focusedCell: null,
      previousCell: null,
    })

    // ── Event subscriptions ──────────────────

    this.cleanups.push(
      context.eventBus.on(GridEvent.FOCUS_SET_REQUESTED, (payload: unknown) => {
        const { cell } = payload as FocusSetPayload
        this.setFocus(cell)
      })
    )

    this.cleanups.push(
      context.eventBus.on(
        GridEvent.FOCUS_MOVE_REQUESTED,
        (payload: unknown) => {
          const { direction, editableOnly } = payload as FocusMovePayload
          this.moveFocus(direction, editableOnly ?? false)
        }
      )
    )

    // Clear focus when data changes — the focused rowId may no longer exist
    this.cleanups.push(
      context.eventBus.on(GridEvent.DATA_SET, () => this.clearFocus())
    )
    this.cleanups.push(
      context.eventBus.on(GridEvent.DATA_CHANGED, () => this.clearFocus())
    )

    // Clear focus on page change — focused row likely not on new page
    this.cleanups.push(
      context.eventBus.on(GridEvent.PAGE_CHANGED, () => this.clearFocus())
    )
  }

  // ── Public API ────────────────────────────
  // These are also callable directly by other plugins and the adapter.

  getFocusedCell(): CellPosition | null {
    return this.context.store.read('focus').focusedCell
  }

  setFocus(cell: CellPosition): void {
    const previous = this.getFocusedCell()

    // No-op if already focused on the same cell
    if (
      previous?.rowId === cell.rowId &&
      previous?.columnId === cell.columnId
    ) {
      return
    }

    this.context.store.write('focus', {
      focusedCell: cell,
      previousCell: previous,
    })

    this.context.eventBus.emit(GridEvent.FOCUS_CHANGED, {
      cell,
      previousCell: previous,
    } satisfies FocusChangedPayload)
  }

  clearFocus(): void {
    const previous = this.getFocusedCell()
    if (!previous) return // already clear

    this.context.store.write('focus', {
      focusedCell: null,
      previousCell: previous,
    })

    this.context.eventBus.emit(GridEvent.FOCUS_CHANGED, {
      cell: null,
      previousCell: previous,
    } satisfies FocusChangedPayload)
  }

  moveFocus(direction: FocusDirection, editableOnly = false): void {
    const current = this.getFocusedCell()

    // No current focus — move to first cell to establish it
    if (!current) {
      const first = this.resolveFirst(editableOnly)
      if (first) this.setFocus(first)
      return
    }

    const next = this.resolve(current, direction, editableOnly)
    if (next) this.setFocus(next)
    // If resolve returns null — we're at a boundary, no-op (don't lose focus)
  }

  // ── Navigation resolution ─────────────────
  // Pure math — reads from store, returns next CellPosition or null.
  // Null means "boundary reached, stay put".

  resolve(
    from: CellPosition,
    direction: FocusDirection,
    editableOnly = false
  ): CellPosition | null {
    const rowIds = this.getRowIds()
    const colIds = this.getColumnIds(editableOnly)

    if (rowIds.length === 0 || colIds.length === 0) return null

    const rowIdx = rowIds.indexOf(from.rowId)
    const colIdx = colIds.indexOf(from.columnId)

    // If current cell is not in the visible/editable set — snap to nearest
    const safeRowIdx = rowIdx === -1 ? 0 : rowIdx
    const safeColIdx = colIdx === -1 ? 0 : colIdx

    switch (direction) {
      case 'up':
        return this.resolveUp(rowIds, colIds, safeRowIdx, safeColIdx)
      case 'down':
        return this.resolveDown(rowIds, colIds, safeRowIdx, safeColIdx)
      case 'left':
        return this.resolveLeft(rowIds, colIds, safeRowIdx, safeColIdx)
      case 'right':
        return this.resolveRight(rowIds, colIds, safeRowIdx, safeColIdx)
      case 'next':
        return this.resolveNext(rowIds, colIds, safeRowIdx, safeColIdx)
      case 'prev':
        return this.resolvePrev(rowIds, colIds, safeRowIdx, safeColIdx)
      case 'rowStart':
        return this.makeCell(rowIds, colIds, safeRowIdx, 0)
      case 'rowEnd':
        return this.makeCell(rowIds, colIds, safeRowIdx, colIds.length - 1)
      case 'first':
        return this.resolveFirst(editableOnly)
      case 'last':
        return this.resolveLast(editableOnly)
    }
  }

  // ── Direction resolvers ───────────────────

  private resolveUp(
    rowIds: string[],
    colIds: ColumnId[],
    rowIdx: number,
    colIdx: number
  ): CellPosition | null {
    if (rowIdx === 0) return null // already at top
    return this.makeCell(rowIds, colIds, rowIdx - 1, colIdx)
  }

  private resolveDown(
    rowIds: string[],
    colIds: ColumnId[],
    rowIdx: number,
    colIdx: number
  ): CellPosition | null {
    if (rowIdx === rowIds.length - 1) return null // already at bottom
    return this.makeCell(rowIds, colIds, rowIdx + 1, colIdx)
  }

  private resolveLeft(
    rowIds: string[],
    colIds: ColumnId[],
    rowIdx: number,
    colIdx: number
  ): CellPosition | null {
    if (colIdx === 0) return null // already at first column
    return this.makeCell(rowIds, colIds, rowIdx, colIdx - 1)
  }

  private resolveRight(
    rowIds: string[],
    colIds: ColumnId[],
    rowIdx: number,
    colIdx: number
  ): CellPosition | null {
    if (colIdx === colIds.length - 1) return null // already at last column
    return this.makeCell(rowIds, colIds, rowIdx, colIdx + 1)
  }

  // next — Tab: advance column, wrap to next row, stop at last cell
  private resolveNext(
    rowIds: string[],
    colIds: ColumnId[],
    rowIdx: number,
    colIdx: number
  ): CellPosition | null {
    let nextCol = colIdx + 1
    let nextRow = rowIdx

    if (nextCol >= colIds.length) {
      // Wrap to next row
      nextCol = 0
      nextRow = rowIdx + 1
    }

    if (nextRow >= rowIds.length) return null // at last cell — no wrap
    return this.makeCell(rowIds, colIds, nextRow, nextCol)
  }

  // prev — Shift+Tab: go back column, wrap to previous row
  private resolvePrev(
    rowIds: string[],
    colIds: ColumnId[],
    rowIdx: number,
    colIdx: number
  ): CellPosition | null {
    let prevCol = colIdx - 1
    let prevRow = rowIdx

    if (prevCol < 0) {
      // Wrap to previous row
      prevCol = colIds.length - 1
      prevRow = rowIdx - 1
    }

    if (prevRow < 0) return null // at first cell — no wrap
    return this.makeCell(rowIds, colIds, prevRow, prevCol)
  }

  private resolveFirst(editableOnly: boolean): CellPosition | null {
    const rowIds = this.getRowIds()
    const colIds = this.getColumnIds(editableOnly)
    if (rowIds.length === 0 || colIds.length === 0) return null
    return this.makeCell(rowIds, colIds, 0, 0)
  }

  private resolveLast(editableOnly: boolean): CellPosition | null {
    const rowIds = this.getRowIds()
    const colIds = this.getColumnIds(editableOnly)
    if (rowIds.length === 0 || colIds.length === 0) return null
    return this.makeCell(rowIds, colIds, rowIds.length - 1, colIds.length - 1)
  }

  // ── Store readers ─────────────────────────

  // Row IDs from paginated store — these are the currently visible rows.
  // We get IDs from RowModelPlugin (which has the correctly extracted _id
  // for any rowId config) rather than reading r['id'] from raw row data,
  // which would break with any custom rowId configuration.
  private getRowIds(): string[] {
    const rowModel = this.context.getPlugin<RowModelPlugin>(ROW_MODEL_PLUGIN_ID)

    if (rowModel) {
      // Get paginated rows and look up each one's engine ID via RowModelPlugin.
      // RowModelPlugin stores a reverse lookup: _data reference → _id.
      // Simplest correct approach: get all row IDs in order from RowModelPlugin,
      // then filter to only those present in the current paginated set.
      const { rows: paginatedRows } = this.context.store.read('paginated')
      const allIds = rowModel.getRowIds()

      // Build a Set of paginated row positions for O(1) lookup.
      // Since paginated rows are slices of the sorted rows (plain TData),
      // we use the index position within the paginated slice to look up
      // the corresponding ID from RowModelPlugin in order.
      // The paginated store rows are in the same order as the sorted store,
      // which is the same order as RowModelPlugin's row order after filtering.
      // So we can safely use the count to slice allIds to the paginated window.
      const { currentPage, pageSize } = this.context.store.read('paginated')
      const startIndex = (currentPage - 1) * pageSize
      return allIds.slice(startIndex, startIndex + paginatedRows.length)
    }

    // Fallback when RowModelPlugin is not registered (standalone use)
    const { rows } = this.context.store.read('paginated')
    return (rows as Array<Record<string, unknown>>).map((r) => String(r['id']))
  }

  // Visible column IDs — optionally filtered to editable-only for Tab nav
  private getColumnIds(editableOnly: boolean): ColumnId[] {
    const { definitions, order } = this.context.store.read('columns')

    return order.filter((id) => {
      const col = definitions.find((d) => d.id === id)
      if (!col) return false
      if (col.visible === false) return false
      if (editableOnly && !col.editable) return false
      return true
    })
  }

  // ── Cell factory ──────────────────────────
  // Builds a CellPosition from indices — single place where indices → ids

  private makeCell(
    rowIds: string[],
    colIds: ColumnId[],
    rowIdx: number,
    colIdx: number
  ): CellPosition | null {
    const rowId = rowIds[rowIdx]
    const columnId = colIds[colIdx]
    if (!rowId || !columnId) return null
    return { rowId, columnId, rowIndex: rowIdx, columnIndex: colIdx }
  }

  // ── Destroy ───────────────────────────────

  destroy(): void {
    // Unsubscribe all event bus listeners — prevents zombie handlers on remount
    this.cleanups.forEach((cleanup) => cleanup())
    this.cleanups = []

    this.context.store.write('focus', {
      focusedCell: null,
      previousCell: null,
    })
  }
}
