// ============================================
// @elitegrid/vue — useGridStates
// State composables — one per store namespace.
//
// IDEOLOGY:
// Each composable subscribes to EXACTLY ONE namespace.
// A scroll event re-renders only the body (viewport changed).
// A column resize re-renders only the header (columns changed).
// They never cross-trigger each other — the namespace boundary
// IS the re-render boundary.
//
// Mirror of React's `useViewportState` / `useColumnsState` / etc.
// ============================================

import { shallowRef, onMounted, onBeforeUnmount, type Ref } from 'vue'
import type {
  ViewportNamespace,
  ColumnsNamespace,
  PaginatedNamespace,
  FilteredNamespace,
  SortedNamespace,
  RawNamespace,
  SelectionNamespace,
  EditingNamespace,
  FocusNamespace,
} from '@elitegrid/core'
import type { GridInstance } from '../create-grid'
import { useStoreNamespace } from './useStoreNamespace'

// Used by GridBody — re-renders when visible rows / scroll position change
export function useViewportState(
  grid: GridInstance
): Readonly<Ref<ViewportNamespace>> {
  return useStoreNamespace(grid, 'viewport') as Readonly<Ref<ViewportNamespace>>
}

// Used by GridHeader — re-renders when column definitions / widths change
export function useColumnsState(
  grid: GridInstance
): Readonly<Ref<ColumnsNamespace>> {
  return useStoreNamespace(grid, 'columns') as Readonly<Ref<ColumnsNamespace>>
}

// Used by GridPagination — re-renders when page / pageSize change
export function usePaginationState(
  grid: GridInstance
): Readonly<Ref<PaginatedNamespace>> {
  return useStoreNamespace(grid, 'paginated') as Readonly<
    Ref<PaginatedNamespace>
  >
}

// Used by GridHeader — re-renders when sort model changes
export function useSortedState(
  grid: GridInstance
): Readonly<Ref<SortedNamespace>> {
  return useStoreNamespace(grid, 'sorted') as Readonly<Ref<SortedNamespace>>
}

// Used by GridHeader — re-renders when filter model changes so the
// filter icon color updates immediately on Apply (without depending on
// some other reactive ref triggering a re-render).
export function useFilteredState(
  grid: GridInstance
): Readonly<Ref<FilteredNamespace>> {
  return useStoreNamespace(grid, 'filtered') as Readonly<Ref<FilteredNamespace>>
}

// Used by GridOverlay — re-renders on loading / error / data change
export function useRawState(grid: GridInstance): Readonly<Ref<RawNamespace>> {
  return useStoreNamespace(grid, 'raw') as Readonly<Ref<RawNamespace>>
}

// Used by GridRow and GridHeader — re-renders when selection set changes
export function useSelectionState(
  grid: GridInstance
): Readonly<Ref<SelectionNamespace>> {
  return useStoreNamespace(grid, 'selection') as Readonly<
    Ref<SelectionNamespace>
  >
}

// Used by GridCell — re-renders when an editor opens or commits
export function useEditState(
  grid: GridInstance
): Readonly<Ref<EditingNamespace>> {
  return useStoreNamespace(grid, 'editing') as Readonly<Ref<EditingNamespace>>
}

// Used by GridCell / GridBody — re-renders when focused cell changes
export function useFocusState(
  grid: GridInstance
): Readonly<Ref<FocusNamespace>> {
  return useStoreNamespace(grid, 'focus') as Readonly<Ref<FocusNamespace>>
}

// ─────────────────────────────────────────────
// Per-row / per-cell derived selectors
// ─────────────────────────────────────────────
// These return a reactive boolean for a SINGLE rowId (and optional columnId).
// GridRow / GridCell use them instead of the full selection / focus / edit
// namespace — without them, every visible row would re-render on every
// selection / focus / edit change (O(n) on every click).

export function useCellSelected(
  grid: GridInstance,
  rowId: string
): Readonly<Ref<boolean>> {
  const state = shallowRef(
    grid.kernel.store.read('selection').selectedIds.has(rowId)
  )
  let unsubscribe: (() => void) | null = null

  onMounted(() => {
    // Re-read in case selection changed between setup() and onMounted().
    state.value = grid.kernel.store.read('selection').selectedIds.has(rowId)
    unsubscribe = grid.kernel.store.subscribe('selection', () => {
      // Read directly from the store rather than trusting the payload —
      // some plugins mutate selectedIds in place rather than replacing it.
      state.value = grid.kernel.store.read('selection').selectedIds.has(rowId)
    })
  })

  onBeforeUnmount(() => {
    unsubscribe?.()
    unsubscribe = null
  })

  return state
}

export function useCellFocused(
  grid: GridInstance,
  rowId: string,
  columnId: string
): Readonly<Ref<boolean>> {
  const read = () => {
    const { focusedCell } = grid.kernel.store.read('focus')
    return focusedCell?.rowId === rowId && focusedCell?.columnId === columnId
  }
  const state = shallowRef(read())
  let unsubscribe: (() => void) | null = null

  onMounted(() => {
    state.value = read()
    unsubscribe = grid.kernel.store.subscribe('focus', () => {
      state.value = read()
    })
  })

  onBeforeUnmount(() => {
    unsubscribe?.()
    unsubscribe = null
  })

  return state
}

export function useCellEditing(
  grid: GridInstance,
  rowId: string,
  columnId: string
): Readonly<Ref<boolean>> {
  const read = () => {
    const s = grid.kernel.store.read('editing')
    return (
      s.isEditing &&
      s.editingCell?.rowId === rowId &&
      s.editingCell?.columnId === columnId
    )
  }
  const state = shallowRef(read())
  let unsubscribe: (() => void) | null = null

  onMounted(() => {
    state.value = read()
    unsubscribe = grid.kernel.store.subscribe('editing', () => {
      state.value = read()
    })
  })

  onBeforeUnmount(() => {
    unsubscribe?.()
    unsubscribe = null
  })

  return state
}
